_QTY_MISHEAR_MAP = {
    "fine": "five", "file": "five", "fife": "five", "fire": "five", "hive": "five", "vive": "five", "wife": "five",
    "tree": "three", "free": "three",
    "sex": "six", "sicks": "six",
    "fore": "four",
    "won": "one",
}

def _clean_tokens(text: str):
    t = (text or "").lower()
    t = t.replace("-", " ")
    t = re.sub(r"[,/\.]", " ", t)
    t = re.sub(r"[^a-z0-9\s]", " ", t)
    return [x for x in t.split() if x]

def parse_id_digits(text: str) -> Optional[str]:
    if not text: return None
    digits = re.findall(r"\d", text)
    if digits:
        return "".join(digits)
    out = []
    for tok in _clean_tokens(text):
        if tok in _DIGIT_WORD:
            out.append(_DIGIT_WORD[tok])
    return "".join(out) if out else None

def parse_quantity_digits(text: str) -> Optional[int]:
    if not text:
        return None
    m = re.search(r"\d+", text)
    if m:
        try:
            return int(m.group(0))
        except:
            return None
    tokens = _clean_tokens(text)
    digits = []
    for tok in tokens:
        if tok in _DIGIT_WORD:
            digits.append(_DIGIT_WORD[tok])
        else:
            if digits:
                break
    if digits:
        try:
            return int("".join(digits))
        except:
            return None
    return None

def _words_to_int(tokens):
    total, current = 0, 0
    for t in tokens:
        if t == "hundred":
            current = max(1, current) * 100
        elif t == "thousand":
            current = max(1, current) * 1000
            total += current; current = 0
        elif t in _NUM_WORDS and _NUM_WORDS[t] < 100:
            val = _NUM_WORDS[t]
            if current >= 20 and current % 10 == 0 and val < 10:
                current += val
            else:
                current += val
        else:
            total += current; current = 0
    total += current
    return total if total > 0 else None

def parse_spoken_quantity(text: str) -> Optional[int]:
    if not text: return None
    m = re.search(r"\d+", text)
    if m:
        try: return int(m.group(0))
        except: pass
    tokens = _clean_tokens(text)
    for t in tokens:
        if t in ("couple","dozen","few"): return _NUM_WORDS[t]
    number_tokens = [t for t in tokens if t in _NUM_WORDS or t in ("hundred","thousand")]
    return _words_to_int(number_tokens) if number_tokens else None

def parse_quantity(text: str) -> Optional[int]:
    v = parse_spoken_quantity(text)
    if v is not None:
        logging.info(f"[QTY] Parsed spoken quantity '{text}' -> {v}")
        return v
    v2 = parse_quantity_digits(text)
    logging.info(f"[QTY] Parsed digit quantity '{text}' -> {v2}")
    return v2

def parse_component_quantity(text: str) -> Optional[int]:
    if not text:
        return None

    m = re.search(r"\d+", text)
    if m:
        try:
            return int(m.group(0))
        except Exception:
            pass

    q = parse_spoken_quantity(text)
    if q is not None:
        return q
    q = parse_quantity_digits(text)
    if q is not None:
        return q

    toks = _clean_tokens(text)
    fixed = [_QTY_MISHEAR_MAP.get(t, t) for t in toks]
    fixed_text = " ".join(fixed)

    q = parse_spoken_quantity(fixed_text)
    if q is not None:
        return q
    q = parse_quantity_digits(fixed_text)
    return q

