# ---- music player ----
class MusicPlayer:
    def __init__(self):
        self.playlist, self.current_index = [], 0
        self.playing, self.process = False, None
        self.playlist_lock, self.player_thread = Lock(), None
        self.stop_event = Event()
    def build_playlist(self, category=None, specific=None):
        with self.playlist_lock:
            self.playlist = []
            folder_path = os.path.join(MUSIC_FOLDER, category or "general")
            if specific:
                track_path = os.path.join(folder_path, specific)
                if os.path.exists(track_path):
                    self.playlist = [track_path]
                else:
                    try:
                        files = [f for f in os.listdir(folder_path) if f.endswith(".mp3")]
                        sl = specific.lower()
                        for f in files:
                            if sl in f.lower():
                                self.playlist.append(os.path.join(folder_path, f))
                    except Exception:
                        pass
            else:
                try:
                    files = [f for f in os.listdir(folder_path) if f.endswith(".mp3")]
                    self.playlist = [os.path.join(folder_path, f) for f in files]
                    random.shuffle(self.playlist)
                except Exception:
                    pass
            self.current_index = 0
            return len(self.playlist)
    def start_playback(self, category=None, specific=None):
        self.stop_playback(); self.stop_event.clear()
        if self.build_playlist(category, specific) == 0: return False
        self.playing = True
        self.player_thread = Thread(target=self._playback_loop, daemon=True); self.player_thread.start()
        return True
    def _playback_loop(self):
        while not self.stop_event.is_set() and self.playlist:
            with self.playlist_lock:
                if self.current_index >= len(self.playlist): self.current_index = 0
                current_song = self.playlist[self.current_index]; self.current_index += 1
            try:
                self.process = subprocess.Popen(["mpg123", "-o", "pulse", current_song])
                self.process.wait()
                if self.process.returncode != 0: logging.warning(f"Song playback failed: {current_song}")
                if self.stop_event.is_set(): break
                with self.playlist_lock:
                    if self.current_index >= len(self.playlist): self.current_index = 0
            except Exception as e:
                logging.error(f"Playback error: {e}")
        self.playing = False; self.process = None
    def stop_playback(self):
        self.stop_event.set()
        if self.process and self.process.poll() is None:
            self.process.terminate()
            try: self.process.wait(timeout=2)
            except subprocess.TimeoutExpired: self.process.kill()
        self.playing = False

music_player = MusicPlayer()
def play_music(category=None, track=None):
    music_player.start_playback(category, track)
def stop_music():
    music_player.stop_playback()

