# Active/Sleep state tracking for self-learning
# ====================================================
ROBOT_STATE_LOCK = Lock()
ROBOT_STATE = {
    "is_active": False,
    "sleep_since": None,   # epoch seconds when sleep began
}

def set_robot_active(active: bool):
    now = time.time()
    with ROBOT_STATE_LOCK:
        prev = ROBOT_STATE["is_active"]
        ROBOT_STATE["is_active"] = bool(active)
        if active:
            ROBOT_STATE["sleep_since"] = None
        else:
            # only set sleep start when transitioning active->sleep
            if prev and ROBOT_STATE["sleep_since"] is None:
                ROBOT_STATE["sleep_since"] = now

def get_robot_state():
    with ROBOT_STATE_LOCK:
        return ROBOT_STATE["is_active"], ROBOT_STATE["sleep_since"]

def self_discovery_loop():
    """
    While sleeping:
      - wait 5 min after sleep start
      - capture+discover every 20 min
    Automatically pauses when robot becomes active.
    """
    next_run = None

    while True:
        try:
            if not SELF_LEARN_ENABLED:
                time.sleep(5)
                continue

            is_active, sleep_since = get_robot_state()

            if is_active:
                next_run = None
                time.sleep(1)
                continue

            if not sleep_since:
                next_run = None
                time.sleep(1)
                continue

            now = time.time()
            if (now - sleep_since) < SELF_LEARN_SLEEP_DELAY_SEC:
                next_run = None
                time.sleep(1)
                continue

            # first run exactly at sleep_since + delay
            if next_run is None:
                next_run = sleep_since + SELF_LEARN_SLEEP_DELAY_SEC

            if now >= next_run:
                run_self_discovery_once()
                next_run = now + SELF_LEARN_INTERVAL_SEC

            time.sleep(1)

        except Exception:
            logging.exception("self_discovery_loop error")
            time.sleep(5)
