timers, timer_lock = {}, Lock()
def parse_duration(text):
    m1 = re.search(r"(\d+)\s*(minute|minutes|min)", text or "")
    m2 = re.search(r"(\d+)\s*(second|seconds|sec)", text or "")
    s = 0
    if m1: s += int(m1.group(1)) * 60
    if m2: s += int(m2.group(1))
    return s if s > 0 else None

def start_timer(duration):
    tid = str(uuid4())
    def t():
        global active_timer_remaining
        with active_timer_lock: active_timer_remaining = duration
        while active_timer_remaining > 0:
            time.sleep(1)
            with active_timer_lock: active_timer_remaining -= 1
        play_tts_response("Time is up!")
        with timer_lock: timers.pop(tid, None)
    with timer_lock:
        timers[tid] = Thread(target=t, daemon=True); timers[tid].start()
    return tid

def cancel_all_timers():
    global active_timer_remaining
    with timer_lock: timers.clear()
    with active_timer_lock: active_timer_remaining = None
    play_tts_response("All timers cancelled.")

# ---- weather (FIXED) ----
def get_weather(city_name: Optional[str] = None) -> str:
    """
    Reliable weather in Celsius + short forecast.
    Uses wttr.in JSON (format=j1). Returns a short, TTS-friendly string.
    Never raises (always returns a string).
    """
    DEG = "\N{DEGREE SIGN}"  # "ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â°"

    # Normalize input
    city = (city_name or "").strip()
    city_lc = city.lower()

    # If user didn't specify a city, use auto-location based on IP
    # wttr supports empty / "autoip"
    if (not city) or city_lc in {"your location", "my location", "here", "current location", "location", "auto"}:
        city = "autoip"

    url = f"https://wttr.in/{city}"
    params = {"format": "j1"}  # JSON

    try:
        r = requests.get(
            url,
            params=params,
            timeout=8,
            headers={"User-Agent": "ela-weather/1.0"}
        )
        r.raise_for_status()

        # Force correct decoding (prevents ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã¢â‚¬Â¦Ãƒâ€šÃ‚Â¡ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â°C / mojibake issues)
        r.encoding = "utf-8"

        data = r.json()

        # Current condition
        cur = (data.get("current_condition") or [{}])[0]
        desc = ((cur.get("weatherDesc") or [{"value": "unknown"}])[0].get("value")) or "unknown"

        temp_c = cur.get("temp_C")
        feels_c = cur.get("FeelsLikeC")
        humidity = cur.get("humidity")

        # Optional: nearest area (nice when using autoip)
        area = ""
        try:
            area = ((data.get("nearest_area") or [{}])[0].get("areaName") or [{}])[0].get("value") or ""
        except Exception:
            area = ""

        # Forecast (today + tomorrow)
        weather_days = data.get("weather") or []
        def day_summary(day_obj):
            if not day_obj:
                return None
            date = day_obj.get("date", "")
            maxt = day_obj.get("maxtempC", "")
            mint = day_obj.get("mintempC", "")
            hourly = day_obj.get("hourly") or []
            midday = hourly[len(hourly)//2] if hourly else {}
            ddesc = ((midday.get("weatherDesc") or [{"value": ""}])[0].get("value")) or ""
            if date and maxt != "" and mint != "":
                # Keep short for TTS
                if ddesc:
                    return f"{date}: {mint}{DEG}C to {maxt}{DEG}C, {ddesc}"
                return f"{date}: {mint}{DEG}C to {maxt}{DEG}C"
            return None

        today = day_summary(weather_days[0]) if len(weather_days) > 0 else None
        tomorrow = day_summary(weather_days[1]) if len(weather_days) > 1 else None

        place = f" in {area}" if area else (f" in {city}" if city != "autoip" else "")

        parts = []
        if temp_c is not None:
            parts.append(f"The weather{place} is {desc} with {temp_c}{DEG}C")
        else:
            parts.append(f"The weather{place} is {desc}")

        if feels_c is not None:
            parts.append(f"Feels like {feels_c}{DEG}C")
        if humidity is not None:
            parts.append(f"Humidity {humidity}%")

        if today:
            parts.append(f"Today: {today}")
        if tomorrow:
            parts.append(f"Tomorrow: {tomorrow}")

        return ". ".join(parts) + "."

    except requests.exceptions.Timeout:
        return "Sorry, the weather service timed out. Please try again."
    except requests.exceptions.HTTPError:
        return "Sorry, I couldn't fetch the weather right now."
    except Exception as e:
        logging.error(f"Weather fetch error: {e}")
        return "Sorry, I couldn't get the weather right now."

# ---- PCA9685 demos ----
def hand():
    """
    NEW behavior (as requested):
    - CH0 + CH1 move smoothly in the SAME physical direction
    - Sequence: 90 -> 120 -> 150 -> 90
    - Repeat: 3 times
    - Keeps the same keyword triggers and same TTS text: "Hand task complete."
    """
    # --- Servo calibration (MG995 typical) ---
    SERVO_MIN_US = 500
    SERVO_MAX_US = 2500
    FREQ_HZ = 50

    # Movement plan (logical angles)
    CENTER = 90
    SEQ = [CENTER, CENTER + 30, CENTER + 60, CENTER]  # 90 -> 120 -> 150 -> 90
    REPEAT = 3

    # Smoothness controls
    STEP_DEG = 1
    STEP_DELAY = 0.02

    # If a channel moves opposite physically, invert it here:
    INVERT = {
        0: False,  # CH0 normal
        1: True,   # CH1 inverted so it moves same physical direction as CH0
    }

    def angle_to_duty_cycle(angle_deg: float, freq_hz: int = FREQ_HZ) -> int:
        angle_deg = max(0.0, min(180.0, float(angle_deg)))
        pulse_us = SERVO_MIN_US + (angle_deg / 180.0) * (SERVO_MAX_US - SERVO_MIN_US)
        period_us = 1_000_000.0 / float(freq_hz)
        duty = int((pulse_us / period_us) * 0xFFFF)
        return max(0, min(0xFFFF, duty))

    def apply_inversion(ch: int, angle_deg: float) -> float:
        return (180.0 - float(angle_deg)) if INVERT.get(ch, False) else float(angle_deg)

    def set_servo(pca: PCA9685, ch: int, angle_deg: float):
        a = apply_inversion(ch, angle_deg)
        pca.channels[ch].duty_cycle = angle_to_duty_cycle(a)

    def move_pair_smooth(pca: PCA9685, ch_a: int, ch_b: int, start_deg: int, end_deg: int):
        if start_deg == end_deg:
            set_servo(pca, ch_a, end_deg)
            set_servo(pca, ch_b, end_deg)
            time.sleep(STEP_DELAY)
            return

        step = STEP_DEG if end_deg > start_deg else -STEP_DEG
        a = start_deg
        while (a <= end_deg and step > 0) or (a >= end_deg and step < 0):
            set_servo(pca, ch_a, a)
            set_servo(pca, ch_b, a)
            time.sleep(STEP_DELAY)
            a += step

        # ensure exact final position
        set_servo(pca, ch_a, end_deg)
        set_servo(pca, ch_b, end_deg)
        time.sleep(STEP_DELAY)

    pca = None
    try:
        i2c = busio.I2C(SCL, SDA)
        pca = PCA9685(i2c)
        pca.frequency = FREQ_HZ

        ch0, ch1 = 0, 1

        # Force initial center
        set_servo(pca, ch0, CENTER)
        set_servo(pca, ch1, CENTER)
        time.sleep(0.5)

        for _ in range(REPEAT):
            for i in range(len(SEQ) - 1):
                move_pair_smooth(pca, ch0, ch1, SEQ[i], SEQ[i + 1])
            time.sleep(0.3)

        play_tts_response("Hand task complete.")

    except Exception as e:
        logging.error(f"Hand movement error: {e}")
        play_tts_response("Sorry, hand movement failed.")
    finally:
        try:
            if pca is not None:
                pca.channels[0].duty_cycle = 0
                pca.channels[1].duty_cycle = 0
                pca.deinit()
        except Exception:
            pass

def leg():
    """
    Smooth movement + updated angles (your requested flow):
    Repeat 10 times:
      1) CH4: center -> +30 (smooth)
      2) CH5: center -> +25 (smooth)
      3) CH4: +30 -> center (smooth)
      4) CH5: +25 -> center (smooth)

    Keeps the same triggers and the same TTS confirmation: "Leg task complete."
    """
    # --- Servo calibration for MG995 (adjust if needed) ---
    SERVO_MIN_US = 500
    SERVO_MAX_US = 2500
    FREQ_HZ = 50

    CENTER_DEG = 30
    CH4_STEP_DEG = 20
    CH5_STEP_DEG = 60
    REPEAT = 5

    # Smoothness controls
    SMOOTH_STEP_DEG = 1       # 1 = smoother, 2 = faster
    SMOOTH_STEP_DELAY = 0.02  # 0.01..0.03 typical

    # Small pause between actions
    PAUSE_BETWEEN_ACTIONS = 0.08

    def angle_to_duty_cycle(angle_deg: float, freq_hz: int = FREQ_HZ) -> int:
        angle_deg = max(0.0, min(180.0, float(angle_deg)))
        pulse_us = SERVO_MIN_US + (angle_deg / 180.0) * (SERVO_MAX_US - SERVO_MIN_US)
        period_us = 1_000_000.0 / float(freq_hz)
        duty = int((pulse_us / period_us) * 0xFFFF)
        return max(0, min(0xFFFF, duty))

    def set_servo(pca: PCA9685, ch: int, angle_deg: float):
        pca.channels[ch].duty_cycle = angle_to_duty_cycle(angle_deg)

    def move_smooth(pca: PCA9685, ch: int, start_deg: int, end_deg: int):
        if start_deg == end_deg:
            set_servo(pca, ch, end_deg)
            time.sleep(SMOOTH_STEP_DELAY)
            return

        step = SMOOTH_STEP_DEG if end_deg > start_deg else -SMOOTH_STEP_DEG
        a = start_deg
        while (a <= end_deg and step > 0) or (a >= end_deg and step < 0):
            set_servo(pca, ch, a)
            time.sleep(SMOOTH_STEP_DELAY)
            a += step

        # ensure exact final position
        set_servo(pca, ch, end_deg)
        time.sleep(SMOOTH_STEP_DELAY)

    pca = None
    try:
        i2c = busio.I2C(SCL, SDA)
        pca = PCA9685(i2c)
        pca.frequency = FREQ_HZ

        ch4, ch5 = 4, 5
        ch4_up = CENTER_DEG + CH4_STEP_DEG
        ch5_up = CENTER_DEG + CH5_STEP_DEG

        # Initialize both to center
        set_servo(pca, ch4, CENTER_DEG)
        set_servo(pca, ch5, CENTER_DEG)
        time.sleep(0.3)

        for _ in range(REPEAT):
            # 1) CH4: center -> +30
            move_smooth(pca, ch4, CENTER_DEG, ch4_up)
            time.sleep(PAUSE_BETWEEN_ACTIONS)

            # 2) CH5: center -> +25
            move_smooth(pca, ch5, CENTER_DEG, ch5_up)
            time.sleep(PAUSE_BETWEEN_ACTIONS)

            # 3) CH4: +30 -> center
            move_smooth(pca, ch4, ch4_up, CENTER_DEG)
            time.sleep(PAUSE_BETWEEN_ACTIONS)

            # 4) CH5: +25 -> center
            move_smooth(pca, ch5, ch5_up, CENTER_DEG)
            time.sleep(PAUSE_BETWEEN_ACTIONS)

        play_tts_response("Leg task complete.")

    except Exception as e:
        logging.error(f"Leg movement error: {e}")
        play_tts_response("Sorry, leg movement failed.")

    finally:
        try:
            if pca is not None:
                pca.channels[4].duty_cycle = 0
                pca.channels[5].duty_cycle = 0
                pca.deinit()
        except Exception:
            pass

def right():
    """
    NEW function (as requested):
    - Keywords: "right movement", "go right" (added in process_command section below)
    - CH12 and CH13 move together from CURRENT position to +30 degrees, then back
    - Repeat: 5 times
    - TTS: "right movement completed"
    """
    SERVO_MIN_US = 500
    SERVO_MAX_US = 2500
    FREQ_HZ = 50

    OFFSET = 30
    REPEAT = 5

    STEP_DEG = 1
    STEP_DELAY = 0.02
    HOLD_DELAY = 0.15

    def angle_to_duty_cycle(angle_deg: float, freq_hz: int = FREQ_HZ) -> int:
        angle_deg = max(0.0, min(180.0, float(angle_deg)))
        pulse_us = SERVO_MIN_US + (angle_deg / 180.0) * (SERVO_MAX_US - SERVO_MIN_US)
        period_us = 1_000_000.0 / float(freq_hz)
        duty = int((pulse_us / period_us) * 0xFFFF)
        return max(0, min(0xFFFF, duty))

    def duty_cycle_to_angle(duty: int, freq_hz: int = FREQ_HZ) -> float:
        # If released (0), assume neutral
        if not duty:
            return 90.0
        period_us = 1_000_000.0 / float(freq_hz)
        pulse_us = (float(duty) / 0xFFFF) * period_us
        angle = (pulse_us - SERVO_MIN_US) / (SERVO_MAX_US - SERVO_MIN_US) * 180.0
        return max(0.0, min(180.0, angle))

    def set_pair(pca: PCA9685, a: float):
        dc = angle_to_duty_cycle(a)
        pca.channels[12].duty_cycle = dc
        pca.channels[13].duty_cycle = dc

    def move_pair_smooth(pca: PCA9685, start_deg: float, end_deg: float):
        start_deg = float(start_deg)
        end_deg = float(end_deg)
        if abs(end_deg - start_deg) < 0.001:
            set_pair(pca, end_deg)
            time.sleep(STEP_DELAY)
            return
        step = STEP_DEG if end_deg > start_deg else -STEP_DEG
        a = start_deg
        while (a <= end_deg and step > 0) or (a >= end_deg and step < 0):
            set_pair(pca, a)
            time.sleep(STEP_DELAY)
            a += step
        set_pair(pca, end_deg)
        time.sleep(STEP_DELAY)

    pca = None
    try:
        i2c = busio.I2C(SCL, SDA)
        pca = PCA9685(i2c)
        pca.frequency = FREQ_HZ

        # "center (servo position at that time)" -> read current PWM duty
        a12 = duty_cycle_to_angle(int(pca.channels[12].duty_cycle))
        a13 = duty_cycle_to_angle(int(pca.channels[13].duty_cycle))
        base = (a12 + a13) / 2.0

        target = max(0.0, min(180.0, base + OFFSET))

        # Ensure we're at base first (deterministic)
        set_pair(pca, base)
        time.sleep(HOLD_DELAY)

        for _ in range(REPEAT):
            move_pair_smooth(pca, base, target)
            time.sleep(HOLD_DELAY)
            move_pair_smooth(pca, target, base)
            time.sleep(HOLD_DELAY)

        play_tts_response("right movement completed")

    except Exception as e:
        logging.error(f"Right movement error: {e}")
        play_tts_response("Sorry, right movement failed.")
    finally:
        try:
            if pca is not None:
                pca.channels[12].duty_cycle = 0
                pca.channels[13].duty_cycle = 0
                pca.deinit()
        except Exception:
            pass


