def ensure_notes_db():
    conn = sqlite3.connect(NOTES_DB)
    c = conn.cursor()

    # Create tables (with a 'num' column used as the visible number: 1..N)
    c.execute("""
    CREATE TABLE IF NOT EXISTS notes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        num INTEGER,
        text TEXT NOT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )""")

    c.execute("""
    CREATE TABLE IF NOT EXISTS tasks (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        num INTEGER,
        text TEXT NOT NULL,
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )""")

    # Ensure num column exists + backfill contiguous numbering + unique index
    def _ensure_num(table: str):
        cols = [r[1].lower() for r in c.execute(f"PRAGMA table_info({table})").fetchall()]
        if "num" not in cols:
            try:
                c.execute(f"ALTER TABLE {table} ADD COLUMN num INTEGER")
            except Exception:
                pass

        rows = c.execute(f"SELECT id FROM {table} ORDER BY id ASC").fetchall()
        n = 1
        for (rid,) in rows:
            c.execute(f"UPDATE {table} SET num=? WHERE id=?", (n, rid))
            n += 1

        c.execute(f"CREATE UNIQUE INDEX IF NOT EXISTS idx_{table}_num ON {table}(num)")

    _ensure_num("notes")
    _ensure_num("tasks")

    conn.commit()
    conn.close()

def _next_num(c, table: str) -> int:
    v = c.execute(f"SELECT COALESCE(MAX(num),0)+1 FROM {table}").fetchone()[0]
    return int(v or 1)

def _add_item(table: str, text: str) -> Optional[int]:
    text = (text or "").strip()
    if not text or table not in ("notes", "tasks"):
        return None

    with NOTES_TASKS_LOCK:
        conn = sqlite3.connect(NOTES_DB)
        c = conn.cursor()
        num = _next_num(c, table)
        c.execute(f"INSERT INTO {table}(num, text) VALUES(?, ?)", (num, text))
        conn.commit()
        conn.close()
        return num  # visible number

def _list_items(table: str, limit: int = 10):
    if table not in ("notes", "tasks"):
        return []
    with NOTES_TASKS_LOCK:
        conn = sqlite3.connect(NOTES_DB)
        c = conn.cursor()
        rows = c.execute(f"SELECT num, text, created_at FROM {table} ORDER BY num ASC").fetchall()
        conn.close()
    return rows[-limit:] if limit and len(rows) > limit else rows

def _delete_item_by_id(table: str, item_id: int) -> bool:
    """
    item_id here is the visible number (num).
    After delete, shift down everything above it so numbering stays contiguous.
    """
    if table not in ("notes", "tasks"):
        return False
    try:
        item_num = int(item_id)
    except Exception:
        return False
    if item_num <= 0:
        return False

    with NOTES_TASKS_LOCK:
        conn = sqlite3.connect(NOTES_DB)
        c = conn.cursor()

        c.execute(f"DELETE FROM {table} WHERE num=?", (item_num,))
        ok = (c.rowcount > 0)

        if ok:
            c.execute(f"UPDATE {table} SET num = num - 1 WHERE num > ?", (item_num,))
            # repair numbering to be safe
            rows = c.execute(f"SELECT id FROM {table} ORDER BY num ASC").fetchall()
            n = 1
            for (rid,) in rows:
                c.execute(f"UPDATE {table} SET num=? WHERE id=?", (n, rid))
                n += 1

        conn.commit()
        conn.close()
        return ok
