def ensure_selflearn_db():
    os.makedirs(SELF_LEARN_DIR, exist_ok=True)
    conn = sqlite3.connect(SELF_LEARN_DB)
    c = conn.cursor()
    c.execute("""
    CREATE TABLE IF NOT EXISTS selflearn (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        ts_utc TEXT NOT NULL,
        image_path TEXT,
        objects_json TEXT NOT NULL
    )
    """)
    conn.commit()
    conn.close()

def _selflearn_add(ts_utc: str, image_path: str, objects: list) -> None:
    try:
        payload = json.dumps(objects, ensure_ascii=False)
    except Exception:
        payload = "[]"

    with SELFLEARN_LOCK:
        conn = sqlite3.connect(SELF_LEARN_DB)
        c = conn.cursor()
        c.execute(
            "INSERT INTO selflearn(ts_utc, image_path, objects_json) VALUES(?,?,?)",
            (ts_utc, image_path or "", payload)
        )
        conn.commit()
        conn.close()

def _selflearn_get_latest(limit: int = 1):
    with SELFLEARN_LOCK:
        conn = sqlite3.connect(SELF_LEARN_DB)
        c = conn.cursor()
        rows = c.execute(
            "SELECT ts_utc, image_path, objects_json FROM selflearn ORDER BY id DESC LIMIT ?",
            (int(limit),)
        ).fetchall()
        conn.close()
    return rows or []

def _extract_json_obj(text: str) -> Optional[dict]:
    """
    Groq sometimes returns extra text; this tries to extract the first {...} JSON object.
    """
    if not text:
        return None
    s = text.strip()

    # Fast path: pure JSON
    try:
        return json.loads(s)
    except Exception:
        pass

    # Try to find a JSON object in the text
    m = re.search(r"\{.*\}", s, flags=re.S)
    if not m:
        return None
    candidate = m.group(0)
    try:
        return json.loads(candidate)
    except Exception:
        return None

def capture_image_selflearn() -> Optional[str]:
    """
    Separate capture to avoid overwriting image.jpg and keep evidence for debugging.
    """
    os.makedirs(SELF_LEARN_DIR, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    image_path = os.path.join(SELF_LEARN_DIR, f"selflearn_{ts}.jpg")

    try:
        with CAMERA_LOCK:
            subprocess.run([
                "rpicam-still", "-o", image_path,
                "--nopreview", "--quality", "90", "--shutter", "10000", "--denoise", "cdn_off"
            ], check=True)
        return image_path if os.path.exists(image_path) else None
    except Exception as e:
        logging.error(f"Selflearn image capture error: {e}")
        return None

def groq_object_discovery(image_path: str) -> list:
    """
    Returns list of objects:
      [{"name": "...", "use": "..."}, ...]
    """
    if not image_path or not os.path.exists(image_path):
        return []

    prompt = (
        "You are a lab robot doing object discovery from a camera image.\n"
        f"Identify up to {SELF_LEARN_MAX_OBJECTS} distinct physical objects that are clearly visible.\n"
        "For each object, provide:\n"
        "- name: a short common name (1-4 words)\n"
        "- use: what it is used for (max 15 words)\n\n"
        "Return STRICT JSON ONLY in this exact schema:\n"
        "{\n"
        '  "objects": [\n'
        '    {"name": "object name", "use": "short use"},\n'
        '    ...\n'
        "  ]\n"
        "}\n"
        'If you cannot identify objects confidently, return: {"objects": []}\n'
    )

    try:
        with GROQ_LOCK:
            resp = groq_client.chat.completions.create(
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "text", "text": prompt},
                        {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{encode_image(image_path)}"}}
                    ]
                }],
                model=GROQ_VISION_MODEL,
                temperature=0.0,
                max_tokens=450
            )
        txt = (resp.choices[0].message.content or "").strip()
        obj = _extract_json_obj(txt)
        if not obj:
            return []
        items = obj.get("objects", [])
        if not isinstance(items, list):
            return []

        cleaned = []
        for it in items:
            if not isinstance(it, dict):
                continue
            name = str(it.get("name", "")).strip()
            use = str(it.get("use", "")).strip()
            if not name:
                continue
            cleaned.append({"name": name, "use": use})
        return cleaned[:SELF_LEARN_MAX_OBJECTS]
    except Exception as e:
        logging.error(f"Groq object discovery failed: {e}")
        return []

# In-memory cache of the latest discovery (so the voice response is instant)
SELFLEARN_CACHE = {"ts_utc": None, "objects": []}
SELFLEARN_CACHE_LOCK = Lock()

def run_self_discovery_once():
    """
    Silent self-learning step.
    Stores objects in DB + updates cache + refreshes selflearn index for recognition fallback.
    """
    img = capture_image_selflearn()
    if not img:
        return

    objs = groq_object_discovery(img)
    if not objs:
        logging.info("Selflearn: no confident objects detected.")
        return

    ts_utc = datetime.datetime.now(datetime.timezone.utc).isoformat(timespec="seconds")
    _selflearn_add(ts_utc, img, objs)

    with SELFLEARN_CACHE_LOCK:
        SELFLEARN_CACHE["ts_utc"] = ts_utc
        SELFLEARN_CACHE["objects"] = objs

    # Refresh index so "what is that" can use the newest selflearn sample immediately
    _selflearn_rebuild_index()

    names = ", ".join([o["name"] for o in objs if o.get("name")])
    logging.info(f"Selflearn: learned objects: {names}")

def speak_what_i_learned():
    """
    For command: "what did you learn" / "what did you self learn"
    """
    # Prefer in-memory cache
    with SELFLEARN_CACHE_LOCK:
        ts = SELFLEARN_CACHE.get("ts_utc")
        objs = SELFLEARN_CACHE.get("objects") or []

    # If cache empty, read from DB
    if not objs:
        rows = _selflearn_get_latest(limit=1)
        if rows:
            try:
                objs = json.loads(rows[0][2])
                ts = rows[0][0]
            except Exception:
                objs = []

    if not objs:
        play_tts_response("I have not self learned anything yet.")
        return True

    # Speak names (and a tiny hint about use)
    names = [o.get("name", "").strip() for o in objs if o.get("name")]
    names = [n for n in names if n]
    if not names:
        play_tts_response("I learned something, but I could not extract object names.")
        return True

    # Keep it short for TTS
    say_names = ", ".join(names[:6])
    # Optionally add 1-2 uses
    uses = []
    for o in objs[:2]:
        n = (o.get("name") or "").strip()
        u = (o.get("use") or "").strip()
        if n and u:
            uses.append(f"{n} is used for {u}")
    extra = ". " + ". ".join(uses) if uses else ""

    play_tts_response(f"I self learned these objects: {say_names}.{extra}")
    return True
