# NEW: Self-learn index for recognition fallback
# ====================================================
SELFLEARN_INDEX_LOCK = Lock()
SELFLEARN_INDEX = []   # list of dicts: {"hash": int, "image": str, "objects": list, "ts": str}

def _selflearn_rebuild_index(max_rows: int = 200):
    """
    Build an in-memory index from the selflearn DB for fast matching.
    Stores hash of each selflearn image and its objects list.
    """
    try:
        rows = _selflearn_get_latest(limit=max_rows)
        idx = []
        for ts_utc, image_path, objects_json in rows:
            if not image_path or not os.path.exists(image_path):
                continue
            try:
                objs = json.loads(objects_json) if objects_json else []
            except Exception:
                objs = []
            if not isinstance(objs, list) or not objs:
                continue
            h = _average_hash_int(image_path)
            if h is None:
                continue
            idx.append({
                "hash": int(h),
                "image": image_path,
                "objects": objs,
                "ts": ts_utc
            })
        with SELFLEARN_INDEX_LOCK:
            SELFLEARN_INDEX.clear()
            SELFLEARN_INDEX.extend(idx)
    except Exception:
        logging.exception("_selflearn_rebuild_index failed")

def _selflearn_candidates_by_hash(qh: int, k: int = SELFLEARN_MATCH_MAX):
    """
    Returns top-k selflearn records by Hamming distance.
    Each record contains candidate image + objects list.
    """
    if qh is None:
        return []

    with SELFLEARN_INDEX_LOCK:
        data = list(SELFLEARN_INDEX)

    if not data:
        _selflearn_rebuild_index()
        with SELFLEARN_INDEX_LOCK:
            data = list(SELFLEARN_INDEX)

    if not data:
        return []

    scored = []
    for rec in data:
        try:
            d = _hamming(int(qh), int(rec["hash"]))
            scored.append((d, rec))
        except Exception:
            continue

    scored.sort(key=lambda x: x[0])
    return [rec for _, rec in scored[:max(1, k)]]

def _groq_pick_object_from_selflearn(query_path: str, candidates: list) -> Optional[str]:
    """
    Ask Groq to pick ONE object name from the candidate selflearn object lists,
    or return 'unknown'.
    """
    if not candidates:
        return None

    # Build a flat unique list of candidate object names
    names = []
    for rec in candidates:
        for o in (rec.get("objects") or []):
            n = (o.get("name") or "").strip()
            if n and n.lower() not in [x.lower() for x in names]:
                names.append(n)

    if not names:
        return None

    try:
        parts = [
            {"type": "text", "text": (
                "You are helping a lab robot identify an object.\n"
                "Look at the QUERY image.\n"
                "Choose EXACTLY ONE object name from the list below if it is clearly visible in the QUERY image.\n"
                "If none match, reply exactly: unknown\n\n"
                "Return ONLY the chosen name or 'unknown'.\n\n"
                f"Candidate object names: {', '.join(names[:30])}"
            )},
            {"type": "text", "text": "QUERY IMAGE:"},
            {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{encode_image(query_path)}"}},
        ]

        # Provide candidate selflearn images as visual context (top few)
        for i, rec in enumerate(candidates[:SELFLEARN_MATCH_MAX], start=1):
            parts.append({"type": "text", "text": f"REFERENCE SELFLEARN IMAGE {i}:"})
            parts.append({"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{encode_image(rec['image'])}"}})

        resp = groq_client.chat.completions.create(
            messages=[{"role": "user", "content": parts}],
            model=GROQ_VISION_MODEL,
            temperature=0.0,
            max_tokens=40
        )
        ans = (resp.choices[0].message.content or "").strip()
        if not ans:
            return None
        low = ans.lower().strip()
        if low == "unknown":
            return "unknown"

        # Match to candidate list (case-insensitive)
        for nm in names:
            if low == nm.lower():
                return nm
        for nm in names:
            if nm.lower() in low:
                return nm

        return "unknown"
    except Exception as e:
        logging.error(f"_groq_pick_object_from_selflearn failed: {e}")
        return None
# ---- Notes + Tasks DB (CONTIGUOUS NUMBERING) ----
NOTES_TASKS_LOCK = Lock()
# ---- LAB DB (WAL + NOCASE) ----
def _connect_lab():
    conn = sqlite3.connect(LAB_DB)
    conn.execute("PRAGMA journal_mode=WAL;")
    conn.execute("PRAGMA synchronous=NORMAL;")
    return conn

def _column_exists(conn, table, col) -> bool:
    try:
        cur = conn.execute(f"PRAGMA table_info({table})")
        return any((row[1] or "").lower() == col.lower() for row in cur.fetchall())
    except Exception:
        return False

def ensure_lab_db():
    conn = _connect_lab()
    c = conn.cursor()

    c.execute("""
    CREATE TABLE IF NOT EXISTS components (
        name TEXT PRIMARY KEY COLLATE NOCASE,
        quantity INTEGER NOT NULL,
        location TEXT NOT NULL,
        locker INTEGER NOT NULL
    )""")

    c.execute("""
    CREATE TABLE IF NOT EXISTS students (
        student_id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        dob TEXT,
        email TEXT
    )""")

    if not _column_exists(conn, "students", "email"):
        try:
            c.execute("ALTER TABLE students ADD COLUMN email TEXT")
        except Exception:
            pass

    c.execute("""
    CREATE TABLE IF NOT EXISTS borrow_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        ts DATETIME DEFAULT CURRENT_TIMESTAMP,
        student_id TEXT NOT NULL,
        student_name TEXT NOT NULL,
        item TEXT NOT NULL,
        qty INTEGER NOT NULL,
        remaining INTEGER NOT NULL
    )""")

    c.execute("""
    CREATE TABLE IF NOT EXISTS return_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        ts DATETIME DEFAULT CURRENT_TIMESTAMP,
        student_id TEXT NOT NULL,
        student_name TEXT NOT NULL,
        item TEXT NOT NULL,
        qty INTEGER NOT NULL,
        new_total INTEGER NOT NULL
    )""")

    # Borrow transectional table

    c.execute("""
    CREATE TABLE IF NOT EXISTS borrow_txn (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        borrow_ts TEXT NOT NULL,
        due_ts TEXT NOT NULL,
        student_id TEXT NOT NULL,
        student_name TEXT NOT NULL,
        student_email TEXT,
        item TEXT NOT NULL,
        qty INTEGER NOT NULL,
        returned_qty INTEGER NOT NULL DEFAULT 0,
        last_reminder_ts TEXT,
        reminder_count INTEGER NOT NULL DEFAULT 0
    )""")

    if not _column_exists(conn, "borrow_txn", "student_email"):
        try:
            c.execute("ALTER TABLE borrow_txn ADD COLUMN student_email TEXT")
        except Exception:
            pass

    # indexes
    c.execute("CREATE INDEX IF NOT EXISTS idx_components_locker ON components(locker)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_students_name ON students(name)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_borrow_txn_due ON borrow_txn(due_ts)")
    c.execute("CREATE INDEX IF NOT EXISTS idx_borrow_txn_student_item ON borrow_txn(student_id, item)")

    conn.commit()
    conn.close()

