# ====================================================
# NEW: Borrow tracking (due date + FIFO returns) + overdue reminders
# ====================================================

try:
    from dateutil.relativedelta import relativedelta
    _HAS_RELATIVEDELTA = True
except Exception:
    _HAS_RELATIVEDELTA = False

def _utcnow():
    return datetime.datetime.now(datetime.timezone.utc)

def _add_months(dt_utc: datetime.datetime, months: int) -> datetime.datetime:
    if _HAS_RELATIVEDELTA:
        return dt_utc + relativedelta(months=+months)
    # fallback: approx 30 days/month
    return dt_utc + datetime.timedelta(days=30 * months)

def _parse_iso_dt(s: str) -> Optional[datetime.datetime]:
    if not s:
        return None
    try:
        # supports "+00:00" style
        return datetime.datetime.fromisoformat(s.replace("Z", "+00:00"))
    except Exception:
        return None

def add_borrow_txn(student_id: str, student_name: str, student_email: str,
                   item: str, qty: int) -> Tuple[datetime.datetime, datetime.datetime]:
    """Insert a new borrow transaction with due date."""
    borrow_dt = _utcnow()
    due_dt = _add_months(borrow_dt, BORROW_DUE_MONTHS)

    conn = _connect_lab(); c = conn.cursor()
    c.execute("""
        INSERT INTO borrow_txn(borrow_ts, due_ts, student_id, student_name, student_email, item, qty, returned_qty)
        VALUES(?,?,?,?,?,?,?,0)
    """, (
        borrow_dt.isoformat(timespec="seconds"),
        due_dt.isoformat(timespec="seconds"),
        str(student_id),
        str(student_name),
        (student_email or "").strip(),
        normalize_component_name(item),
        int(qty),
    ))
    conn.commit(); conn.close()
    return borrow_dt, due_dt

def apply_return_fifo(student_id: str, item: str, return_qty: int) -> Tuple[int, int]:
    """
    Apply return qty to the oldest open borrows for (student_id, item).
    Returns: (applied_to_borrows, remaining_unmatched)
    """
    item = normalize_component_name(item)
    conn = _connect_lab()
    conn.isolation_level = None
    c = conn.cursor()

    applied = 0
    remaining = int(return_qty)

    try:
        c.execute("BEGIN IMMEDIATE")
        rows = c.execute("""
            SELECT id, qty, returned_qty
            FROM borrow_txn
            WHERE student_id=? AND item=? COLLATE NOCASE AND returned_qty < qty
            ORDER BY borrow_ts ASC
        """, (str(student_id), item)).fetchall()

        for rid, qty, rqty in rows:
            open_qty = int(qty) - int(rqty)
            if open_qty <= 0:
                continue
            use = min(open_qty, remaining)
            c.execute("UPDATE borrow_txn SET returned_qty = returned_qty + ? WHERE id=?", (use, rid))
            applied += use
            remaining -= use
            if remaining <= 0:
                break

        c.execute("COMMIT")
    except Exception:
        try:
            c.execute("ROLLBACK")
        except Exception:
            pass
        logging.exception("apply_return_fifo failed")
        return 0, int(return_qty)
    finally:
        conn.close()

    return applied, remaining

def export_borrowed_excel(component: Optional[str] = None, only_open: bool = False) -> Optional[bytes]:
    """Export borrow_txn to one Excel file (bytes)."""
    if not OPENPYXL_AVAILABLE:
        return None

    conn = _connect_lab(); c = conn.cursor()

    where = []
    args = []
    if component:
        where.append("bt.item = ? COLLATE NOCASE")
        args.append(normalize_component_name(component))
    if only_open:
        where.append("bt.returned_qty < bt.qty")

    where_sql = ("WHERE " + " AND ".join(where)) if where else ""

    rows = c.execute(f"""
        SELECT
            bt.borrow_ts,
            bt.due_ts,
            bt.item,
            bt.student_name,
            bt.student_id,
            COALESCE(bt.student_email, s.email, '') AS email,
            bt.qty,
            bt.returned_qty,
            (bt.qty - bt.returned_qty) AS outstanding
        FROM borrow_txn bt
        LEFT JOIN students s ON s.student_id = bt.student_id
        {where_sql}
        ORDER BY bt.borrow_ts ASC
    """, args).fetchall()

    conn.close()

    wb = Workbook()
    ws = wb.active
    ws.title = "borrowed"
    ws.append([
        "borrow_date_utc",
        "due_date_utc",
        "component",
        "student_name",
        "student_id",
        "email",
        "qty_borrowed",
        "qty_returned",
        "outstanding"
    ])
    for r in rows:
        ws.append(list(r))

    from io import BytesIO
    bio = BytesIO()
    wb.save(bio)
    return bio.getvalue()

def check_and_send_overdue_reminders():
    """
    Sends reminder emails for overdue borrows (outstanding > 0 and due_ts < now).
    Throttled by OVERDUE_REMINDER_MIN_DAYS per transaction.
    """
    now = _utcnow()
    now_iso = now.isoformat(timespec="seconds")
    cutoff_iso = (now - datetime.timedelta(days=OVERDUE_REMINDER_MIN_DAYS)).isoformat(timespec="seconds")

    conn = _connect_lab(); c = conn.cursor()
    rows = c.execute("""
        SELECT
            bt.id,
            bt.borrow_ts,
            bt.due_ts,
            bt.student_id,
            bt.student_name,
            COALESCE(bt.student_email, s.email, '') AS email,
            bt.item,
            bt.qty,
            bt.returned_qty,
            COALESCE(bt.reminder_count, 0)
        FROM borrow_txn bt
        LEFT JOIN students s ON s.student_id = bt.student_id
        WHERE bt.returned_qty < bt.qty
          AND bt.due_ts <= ?
          AND (bt.last_reminder_ts IS NULL OR bt.last_reminder_ts <= ?)
    """, (now_iso, cutoff_iso)).fetchall()
    conn.close()

    sent = 0
    for rid, borrow_ts, due_ts, sid, sname, email, item, qty, returned_qty, reminder_count in rows:
        email = (email or "").strip()
        if not email:
            continue

        bdt = _parse_iso_dt(borrow_ts)
        ddt = _parse_iso_dt(due_ts)
        if not bdt:
            bdt = now
        if not ddt:
            ddt = now

        outstanding = int(qty) - int(returned_qty)
        if outstanding <= 0:
            continue

        # Convert to local time for nicer email
        try:
            b_local = bdt.astimezone(ZoneInfo(DEFAULT_TZ))
            d_local = ddt.astimezone(ZoneInfo(DEFAULT_TZ))
            b_str = b_local.strftime("%Y-%m-%d %H:%M")
            d_str = d_local.strftime("%Y-%m-%d %H:%M")
        except Exception:
            b_str = str(borrow_ts)
            d_str = str(due_ts)

        subject = f"Lab Reminder: Please return {outstanding}x {item}"
        body = (
            f"Hello {sname},\n\n"
            f"This is a reminder from the lab system.\n\n"
            f"You borrowed: {outstanding}x {item}\n"
            f"Borrow date: {b_str}\n"
            f"Due date (2 months): {d_str}\n\n"
            f"It is more than two months now. Please return the component(s) as soon as possible.\n\n"
            f"Thank you,\nElectronic Lab Assistant (ELA) \n"
        )

        ok, msg = send_simple_email(email, subject, body)
        if ok:
            sent += 1
            try:
                conn2 = _connect_lab(); c2 = conn2.cursor()
                c2.execute("""
                    UPDATE borrow_txn
                    SET last_reminder_ts = ?, reminder_count = reminder_count + 1
                    WHERE id = ?
                """, (now_iso, int(rid)))
                conn2.commit(); conn2.close()
            except Exception:
                logging.exception("Failed to update reminder metadata")

    if sent:
        logging.info(f"Overdue reminders sent: {sent}")

def overdue_reminder_loop():
    """Background loop for overdue reminders."""
    while True:
        try:
            check_and_send_overdue_reminders()
        except Exception:
            logging.exception("overdue_reminder_loop error")
        time.sleep(int(OVERDUE_CHECK_INTERVAL_HOURS * 3600))

# ====================================================
# FACE + OBJECT LEARNING / RECOGNITION (FIXED)
# - Uses face_recognition / OpenCV ORB if available
# - Otherwise FALLS BACK to Groq Vision + perceptual hash (no extra deps)
# ====================================================

faces_lock, objects_lock = Lock(), Lock()

# Local-lib stores (only used if libraries work)
face_encodings, face_labels = [], []          # face_recognition encodings
object_descs, object_labels = [], []          # OpenCV ORB descriptors

# Fallback stores (always available): perceptual hash + stored images
face_hashes, face_img_paths, face_img_labels = [], [], []
object_hashes, object_img_paths, object_img_labels = [], [], []

_HASH_SIZE = 16  # 16 => 256-bit hash

# Distance thresholds (lower = more strict). Adjust if needed.
FACE_HASH_STRICT = 30
FACE_HASH_LOOSE  = 60
OBJECT_HASH_STRICT = 28
OBJECT_HASH_LOOSE  = 58

# How many candidates to send to Groq Vision for final decision
GROQ_MATCH_MAX = 3

def _bitcount(x: int) -> int:
    try:
        return x.bit_count()
    except Exception:
        return bin(x).count("1")

def _hamming(a: int, b: int) -> int:
    return _bitcount(a ^ b)

def _safe_open_image(path: str) -> Optional[Image.Image]:
    try:
        return Image.open(path).convert("RGB")
    except Exception:
        return None

def _center_crop_square(img: Image.Image) -> Image.Image:
    w, h = img.size
    s = min(w, h)
    left = (w - s) // 2
    top = (h - s) // 2
    return img.crop((left, top, left + s, top + s))

def _average_hash_int(image_path: str, hash_size: int = _HASH_SIZE) -> Optional[int]:
    img = _safe_open_image(image_path)
    if img is None:
        return None
    try:
        img = _center_crop_square(img)
        img = img.convert("L").resize((hash_size, hash_size), Image.LANCZOS)
        arr = np.asarray(img, dtype=np.float32)
        avg = float(arr.mean())
        bits = (arr > avg).astype(np.uint8).flatten()
        out = 0
        for b in bits:
            out = (out << 1) | int(b)
        return out
    except Exception:
        return None

def _label_from_filename(path: str) -> str:
    base = os.path.splitext(os.path.basename(path))[0]
    return base.rsplit("_", 1)[0].strip() if "_" in base else base.strip()

def _ensure_storage_dirs():
    os.makedirs(FACES_DIR, exist_ok=True)
    os.makedirs(OBJECTS_DIR, exist_ok=True)
    os.makedirs(MUSIC_FOLDER, exist_ok=True)
    os.makedirs(os.path.join(MUSIC_FOLDER, "general"), exist_ok=True)

def _load_faces_index():
    with faces_lock:
        face_encodings.clear()
        face_labels.clear()
        face_hashes.clear()
        face_img_paths.clear()
        face_img_labels.clear()

        if not os.path.isdir(FACES_DIR):
            return

        # 1) Load face_recognition encodings if present
        for fn in os.listdir(FACES_DIR):
            if fn.endswith(".npy"):
                try:
                    enc = np.load(os.path.join(FACES_DIR, fn))
                    name = fn.rsplit("_", 1)[0]
                    face_encodings.append(enc)
                    face_labels.append(name)
                except Exception as e:
                    logging.warning(f"Skip face encoding {fn}: {e}")

        # 2) Load fallback images
        for fn in os.listdir(FACES_DIR):
            if not fn.lower().endswith((".jpg", ".jpeg", ".png", ".webp")):
                continue
            p = os.path.join(FACES_DIR, fn)
            h = _average_hash_int(p)
            if h is None:
                continue
            lbl = _label_from_filename(p)
            face_hashes.append(h)
            face_img_paths.append(p)
            face_img_labels.append(lbl)

def _load_objects_index():
    with objects_lock:
        object_descs.clear()
        object_labels.clear()
        object_hashes.clear()
        object_img_paths.clear()
        object_img_labels.clear()

        if not os.path.isdir(OBJECTS_DIR):
            return

        # 1) Load ORB descriptors if present
        for fn in os.listdir(OBJECTS_DIR):
            if fn.endswith(".npz"):
                try:
                    data = np.load(os.path.join(OBJECTS_DIR, fn))
                    desc = data["desc"]
                    label = str(data["label"])
                    if desc is None or len(desc) == 0:
                        continue
                    object_descs.append(desc)
                    object_labels.append(label)
                except Exception as e:
                    logging.warning(f"Skip object file {fn}: {e}")

        # 2) Load fallback images
        for fn in os.listdir(OBJECTS_DIR):
            if not fn.lower().endswith((".jpg", ".jpeg", ".png", ".webp")):
                continue
            p = os.path.join(OBJECTS_DIR, fn)
            h = _average_hash_int(p)
            if h is None:
                continue
            lbl = _label_from_filename(p)
            object_hashes.append(h)
            object_img_paths.append(p)
            object_img_labels.append(lbl)

def init_learning_indexes():
    _ensure_storage_dirs()
    _load_faces_index()
    _load_objects_index()

def _orb_extract(image_path: str):
    if not OBJECT_LIB_AVAILABLE or cv2 is None:
        return None
    try:
        img = cv2.imread(image_path, cv2.IMREAD_GRAYSCALE)
        if img is None:
            return None
        orb = cv2.ORB_create(nfeatures=1500)
        kps, desc = orb.detectAndCompute(img, None)
        return desc
    except Exception as e:
        logging.error(f"ORB extract error: {e}")
        return None

def _top_k_by_hash(qh: int, labels: list, paths: list, hashes: list, k: int) -> list:
    if qh is None or not hashes:
        return []
    best_per_label = {}
    for lbl, pth, hh in zip(labels, paths, hashes):
        try:
            d = _hamming(qh, int(hh))
        except Exception:
            continue
        if (lbl not in best_per_label) or (d < best_per_label[lbl][0]):
            best_per_label[lbl] = (d, pth)
    ranked = sorted(best_per_label.items(), key=lambda kv: kv[1][0])
    return [(lbl, pth) for (lbl, (d, pth)) in ranked[:max(1, k)]]

def _groq_pick_best_label(kind: str, query_path: str, candidates: list) -> Optional[str]:
    if not candidates:
        return "unknown"
    try:
        parts = [{"type": "text", "text": (
            f"Task: identify the {kind} in the QUERY image.\n"
            f"Choose EXACTLY ONE label from the candidates, or reply exactly: unknown\n"
            f"Return ONLY the label or 'unknown'."
        )}]
        parts.append({"type": "text", "text": "QUERY:"})
        parts.append({"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{encode_image(query_path)}"}})
        for i, (lbl, pth) in enumerate(candidates, start=1):
            parts.append({"type": "text", "text": f"Candidate {i} label: {lbl}"})
            parts.append({"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{encode_image(pth)}"}})

        resp = groq_client.chat.completions.create(
            messages=[{"role": "user", "content": parts}],
            model=GROQ_VISION_MODEL,
            temperature=0.0,
            max_tokens=30
        )
        ans = (resp.choices[0].message.content or "").strip()
        if not ans:
            return None
        a = ans.lower().strip()
        if a == "unknown":
            return "unknown"
        labels_lower = {lbl.lower(): lbl for (lbl, _) in candidates}
        if a in labels_lower:
            return labels_lower[a]
        for k, v in labels_lower.items():
            if k in a:
                return v
        return "unknown"
    except Exception as e:
        logging.error(f"Groq vision match failed: {e}")
        return None

# -----------------------
# FACE: learn / recognize
# -----------------------
def learn_face(name: str):
    name = re.sub(r"[^\w\s-]", "", (name or "")).strip()
    if not name:
        play_tts_response("Please provide a valid name.")
        return False

    img_path = capture_image()
    if not img_path:
        play_tts_response("Could not capture image.")
        return False

    # Try face_recognition first
    if FACE_LIB_AVAILABLE:
        try:
            img = face_recognition.load_image_file(img_path)
            boxes = face_recognition.face_locations(img, model="hog")
            if not boxes:
                raise RuntimeError("No face detected")
            encs = face_recognition.face_encodings(img, known_face_locations=boxes)
            if not encs:
                raise RuntimeError("No encodings produced")
            enc = encs[0]
            out_fn = f"{name}_{uuid4().hex}.npy"
            np.save(os.path.join(FACES_DIR, out_fn), enc)
            # also save an image for fallback
            out_img = os.path.join(FACES_DIR, f"{name}_{uuid4().hex}.jpg")
            try:
                Image.open(img_path).convert("RGB").save(out_img, "JPEG", quality=92)
            except Exception:
                pass
            _load_faces_index()
            play_tts_response(f"Learned face for {name}.")
            return True
        except Exception as e:
            logging.warning(f"face_recognition failed, fallback: {e}")

    # Fallback: store face image + hash
    try:
        out_img = os.path.join(FACES_DIR, f"{name}_{uuid4().hex}.jpg")
        Image.open(img_path).convert("RGB").save(out_img, "JPEG", quality=92)
        h = _average_hash_int(out_img)
        if h is None:
            play_tts_response("I couldn't process the image for learning.")
            return False
        _load_faces_index()
        play_tts_response(f"Learned face for {name}.")
        return True
    except Exception as e:
        logging.error(f"Learn face fallback error: {e}")
        play_tts_response("Learning face failed.")
        return False

def recognize_face():
    # Prefer face_recognition if available + we have encodings
    if FACE_LIB_AVAILABLE and face_encodings:
        img_path = capture_image()
        if not img_path:
            play_tts_response("Could not capture image.")
            return None
        try:
            img = face_recognition.load_image_file(img_path)
            boxes = face_recognition.face_locations(img, model="hog")
            if not boxes:
                play_tts_response("I cannot see any face.")
                return None
            encs = face_recognition.face_encodings(img, known_face_locations=boxes)
            if not encs:
                play_tts_response("Failed to encode the face.")
                return None
            query = encs[0]
            with faces_lock:
                dists = face_recognition.face_distance(face_encodings, query)
                idx = int(np.argmin(dists))
                dist = float(dists[idx])
                best = face_labels[idx]
            if dist <= FACE_MATCH_THRESHOLD:
                play_tts_response(f"This is {best}.")
                return best
        except Exception as e:
            logging.warning(f"recognize_face face_recognition failed, fallback: {e}")

    # Fallback
    if not face_img_paths:
        play_tts_response("I haven't learned any faces yet.")
        return None

    img_path = capture_image()
    if not img_path:
        play_tts_response("Could not capture image.")
        return None

    qh = _average_hash_int(img_path)
    if qh is None:
        play_tts_response("I couldn't process the image.")
        return None

    cands = _top_k_by_hash(qh, face_img_labels, face_img_paths, face_hashes, GROQ_MATCH_MAX)
    if not cands:
        play_tts_response("I haven't learned any faces yet.")
        return None

    best_lbl, best_p = cands[0]
    best_h = _average_hash_int(best_p)
    best_d = _hamming(qh, best_h) if best_h is not None else 999

    if best_d <= FACE_HASH_STRICT:
        play_tts_response(f"This is {best_lbl}.")
        return best_lbl

    if best_d <= FACE_HASH_LOOSE:
        chosen = _groq_pick_best_label("person", img_path, cands)
        if chosen and chosen != "unknown":
            play_tts_response(f"This is {chosen}.")
            return chosen

    play_tts_response("I don't recognize this person.")
    return "unknown"

# -----------------------
# OBJECT: learn / recognize
# -----------------------
def learn_object(label: str):
    label = re.sub(r"[^\w\s-]", "", (label or "")).strip()
    if not label:
        play_tts_response("Please provide a valid object name.")
        return False

    img_path = capture_image()
    if not img_path:
        play_tts_response("Could not capture image.")
        return False

    # Try ORB first
    if OBJECT_LIB_AVAILABLE and cv2 is not None:
        try:
            desc = _orb_extract(img_path)
            if desc is not None and len(desc) > 0:
                out_fn = f"{label}_{uuid4().hex}.npz"
                np.savez_compressed(os.path.join(OBJECTS_DIR, out_fn), desc=desc, label=label)
                # also save image for fallback
                out_img = os.path.join(OBJECTS_DIR, f"{label}_{uuid4().hex}.jpg")
                try:
                    Image.open(img_path).convert("RGB").save(out_img, "JPEG", quality=92)
                except Exception:
                    pass
                _load_objects_index()
                play_tts_response(f"Learned object {label}.")
                return True
        except Exception as e:
            logging.warning(f"OpenCV ORB failed, fallback: {e}")

    # Fallback: store object image + hash
    try:
        out_img = os.path.join(OBJECTS_DIR, f"{label}_{uuid4().hex}.jpg")
        Image.open(img_path).convert("RGB").save(out_img, "JPEG", quality=92)
        h = _average_hash_int(out_img)
        if h is None:
            play_tts_response("I couldn't process the image for learning.")
            return False
        _load_objects_index()
        play_tts_response(f"Learned object {label}.")
        return True
    except Exception as e:
        logging.error(f"Learn object fallback error: {e}")
        play_tts_response("Learning object failed.")
        return False

def recognize_object():
    """
    Priority:
      1) Object learning DB (ORB / learned objects)
      2) Self-learning DB fallback (sleep discovery)
      3) If not found -> "I did not learn this yet"
    """

    # -----------------------
    # 1) Object-learning DB (ORB)
    # -----------------------
    if OBJECT_LIB_AVAILABLE and cv2 is not None and object_descs:
        img_path = capture_image()
        if not img_path:
            play_tts_response("Could not capture image.")
            return None

        q = _orb_extract(img_path)
        if q is not None and len(q) > 0:
            try:
                bf = cv2.BFMatcher(cv2.NORM_HAMMING, crossCheck=False)
                best, best_good = None, -1
                with objects_lock:
                    for cand, label in zip(object_descs, object_labels):
                        try:
                            matches = bf.knnMatch(q, cand, k=2)
                            good = sum(1 for m, n in matches if m.distance < 0.75 * n.distance)
                            if good > best_good:
                                best_good, best = good, label
                        except Exception:
                            continue

                if best and best_good >= OBJECT_MIN_GOOD_MATCHES:
                    play_tts_response(f"This is {best}.")
                    return best
            except Exception as e:
                logging.warning(f"OpenCV object match failed, fallback: {e}")

    # -----------------------
    # 2) Object-learning DB (hash fallback)
    # -----------------------
    if object_img_paths:
        img_path = capture_image()
        if not img_path:
            play_tts_response("Could not capture image.")
            return None

        qh = _average_hash_int(img_path)
        if qh is not None:
            cands = _top_k_by_hash(qh, object_img_labels, object_img_paths, object_hashes, GROQ_MATCH_MAX)
            if cands:
                best_lbl, best_p = cands[0]
                best_h = _average_hash_int(best_p)
                best_d = _hamming(qh, best_h) if best_h is not None else 999

                if best_d <= OBJECT_HASH_STRICT:
                    play_tts_response(f"This is {best_lbl}.")
                    return best_lbl

                if best_d <= OBJECT_HASH_LOOSE:
                    chosen = _groq_pick_best_label("object", img_path, cands)
                    if chosen and chosen != "unknown":
                        play_tts_response(f"This is {chosen}.")
                        return chosen

    # -----------------------
    # 3) SELF-LEARN fallback
    # -----------------------
    img_path = capture_image()
    if not img_path:
        play_tts_response("Could not capture image.")
        return None

    qh = _average_hash_int(img_path)
    if qh is None:
        play_tts_response("I did not learn this yet.")
        return "unknown"

    self_cands = _selflearn_candidates_by_hash(qh, k=SELFLEARN_MATCH_MAX)
    if not self_cands:
        play_tts_response("I did not learn this yet.")
        return "unknown"

    # Check hash distance quickly
    try:
        d0 = _hamming(int(qh), int(self_cands[0]["hash"]))
    except Exception:
        d0 = 999

    # Strict: if very close, just speak first object name from that record
    if d0 <= SELFLEARN_HASH_STRICT:
        objs = self_cands[0].get("objects") or []
        if objs and isinstance(objs, list):
            nm = (objs[0].get("name") or "").strip()
            if nm:
                play_tts_response(f"This is {nm}.")
                return nm

    # Loose: ask Groq to pick an object name from selflearn candidates
    if d0 <= SELFLEARN_HASH_LOOSE:
        picked = _groq_pick_object_from_selflearn(img_path, self_cands)
        if picked and picked != "unknown":
            play_tts_response(f"This is {picked}.")
            return picked

    play_tts_response("I did not learn this yet.")
    return "unknown"
