def get_calendar_service():
    creds = get_google_credentials()
    if not creds:
        return None
    try:
        return build("calendar", "v3", credentials=creds)
    except Exception as e:
        logging.error(f"Calendar service build failed: {e}")
        return None

def _dt_to_rfc3339(dt: datetime.datetime) -> str:
    # dt must be tz-aware
    return dt.isoformat(timespec="seconds")

def _parse_date_input(date_text: str, tz: str = DEFAULT_TZ) -> Optional[datetime.date]:
    """
    Supports:
      - 02, 05, 2026  (day, month, year)
      - 02 05 2026
      - 02-05-2026
      - 02/05/2026
      - 12 february 2026
      - 2nd february 2026
    """
    t = (date_text or "").strip().lower()
    if not t:
        return None

    # remove ordinal suffix: 1st, 2nd, 3rd, 25th...
    t = re.sub(r"(\d+)(st|nd|rd|th)\b", r"\1", t)

    # Normalize separators
    t_norm = t.replace(",", " ")
    t_norm = t_norm.replace("/", " ")
    t_norm = t_norm.replace("-", " ")
    t_norm = re.sub(r"\s+", " ", t_norm).strip()

    # 1) Strong numeric parse first: D M Y (European style)
    nums = re.findall(r"\d+", t_norm)
    if len(nums) >= 3:
        try:
            day = int(nums[0])
            month = int(nums[1])
            year = int(nums[2])
            if year < 100:  # allow "26" -> 2026
                year += 2000
            if 1 <= day <= 31 and 1 <= month <= 12 and 2000 <= year <= 2100:
                return datetime.date(year, month, day)
        except Exception:
            pass

    # 2) Try dateparser (best for spoken dates like "12 february 2026")
    try:
        import dateparser
        settings = {
            "TIMEZONE": tz,
            "RETURN_AS_TIMEZONE_AWARE": True,
            "PREFER_DATES_FROM": "future",
            "DATE_ORDER": "DMY",
        }
        dt = dateparser.parse(t_norm, settings=settings)
        if dt:
            return dt.date()
    except Exception:
        pass

    # 3) Fallback strptime formats
    fmts = [
        "%d %B %Y",  # 12 february 2026
        "%d %b %Y",  # 12 feb 2026
    ]
    for f in fmts:
        try:
            return datetime.datetime.strptime(t_norm, f).date()
        except Exception:
            pass

    return None
# ---------------------------
# NEW: Split date input helpers (day first, then month+year)
# ---------------------------
_MONTH_MAP = {
    "jan": 1, "january": 1,
    "feb": 2, "february": 2,
    "mar": 3, "march": 3,
    "apr": 4, "april": 4,
    "may": 5,
    "jun": 6, "june": 6,
    "jul": 7, "july": 7,
    "aug": 8, "august": 8,
    "sep": 9, "sept": 9, "september": 9,
    "oct": 10, "october": 10,
    "nov": 11, "november": 11,
    "dec": 12, "december": 12,
}

def _parse_day_only(day_text: str) -> Optional[int]:
    """
    Accepts day only: "01", "1", "12", "first", "2nd", "twelve", etc.
    Returns 1..31 or None.
    """
    t = (day_text or "").strip().lower()
    if not t:
        return None

    # remove ordinal suffix: 1st, 2nd, 3rd, 25th...
    t = re.sub(r"(\d+)(st|nd|rd|th)\b", r"\1", t)

    # digits first
    m = re.search(r"\b(\d{1,2})\b", t)
    if m:
        try:
            d = int(m.group(1))
            return d if 1 <= d <= 31 else None
        except Exception:
            pass

    # words fallback ("twelve", "one", etc.)
    d2 = parse_quantity(t)
    if d2 is not None and 1 <= int(d2) <= 31:
        return int(d2)

    return None

def _parse_month_year(month_year_text: str, tz: str = DEFAULT_TZ) -> Optional[Tuple[int, int]]:
    """
    Accepts: "March 2026", "mar 2026", "3 2026", "03 26"
    Returns (month, year) or None.
    """
    t = (month_year_text or "").strip().lower()
    if not t:
        return None

    # normalize separators
    t = t.replace(",", " ")
    t = t.replace("/", " ")
    t = t.replace("-", " ")
    t = re.sub(r"\s+", " ", t).strip()

    # 1) If dateparser is available, it can parse "march 2026" well
    try:
        import dateparser
        settings = {
            "TIMEZONE": tz,
            "RETURN_AS_TIMEZONE_AWARE": True,
            "PREFER_DATES_FROM": "future",
            "DATE_ORDER": "DMY",
        }
        dt = dateparser.parse("1 " + t, settings=settings)  # force a day
        if dt:
            y = int(dt.year)
            m = int(dt.month)
            if 1 <= m <= 12 and 2000 <= y <= 2100:
                return (m, y)
    except Exception:
        pass

    # 2) Manual parse
    tokens = t.split()
    month = None
    year = None

    for tok in tokens:
        if tok in _MONTH_MAP:
            month = _MONTH_MAP[tok]
            continue

        # numeric month/year
        if re.fullmatch(r"\d{1,4}", tok):
            n = int(tok)
            if n >= 2000:
                year = n
            elif 0 <= n <= 99:
                # treat as year if reasonable, otherwise could be month
                if n >= 25:  # 25 -> 2025 etc (adjust if you want)
                    year = 2000 + n
                else:
                    # could be month like "3"
                    if month is None and 1 <= n <= 12:
                        month = n
            else:
                # 100..1999 not expected; ignore
                pass

    # If we still don't have year, try to find a 4-digit year anywhere
    if year is None:
        m2 = re.search(r"\b(20\d{2})\b", t)
        if m2:
            year = int(m2.group(1))

    if month is not None and year is not None and 1 <= month <= 12 and 2000 <= year <= 2100:
        return (month, year)

    return None
def _parse_time_input_24h(time_text: str, tz: str = DEFAULT_TZ) -> Optional[Tuple[int,int]]:
    """
    Accepts: '14:30', '14 30', '14', 'fourteen thirty' (if dateparser installed).
    """
    t = (time_text or "").strip().lower()
    if not t:
        return None

    # Try dateparser first (handles "fourteen thirty")
    try:
        import dateparser
        settings = {"TIMEZONE": tz, "RETURN_AS_TIMEZONE_AWARE": True}
        dt = dateparser.parse("today at " + t, settings=settings)
        if dt:
            return int(dt.hour), int(dt.minute)
    except Exception:
        pass

    # Digits: 14:30 or 14 30
    m = re.search(r"\b(\d{1,2})(?::|\s+)?(\d{2})?\b", t)
    if not m:
        return None
    hh = int(m.group(1))
    mm = int(m.group(2)) if m.group(2) is not None else 0
    if 0 <= hh <= 23 and 0 <= mm <= 59:
        return hh, mm
    return None

def _calendar_slot_is_free(cal_svc, start_dt: datetime.datetime, end_dt: datetime.datetime) -> bool:
    try:
        items = cal_svc.events().list(
            calendarId="primary",
            timeMin=_dt_to_rfc3339(start_dt),
            timeMax=_dt_to_rfc3339(end_dt),
            singleEvents=True,
            orderBy="startTime",
            maxResults=10
        ).execute().get("items", [])
        return len(items) == 0
    except Exception as e:
        logging.error(f"Calendar conflict check failed: {e}")
        # safer to assume "not free" if we can't check
        return False

def _calendar_add_event(cal_svc, title: str, start_dt: datetime.datetime, end_dt: datetime.datetime, tz: str = DEFAULT_TZ) -> bool:
    try:
        ev = {
            "summary": title,
            "start": {"dateTime": _dt_to_rfc3339(start_dt), "timeZone": tz},
            "end": {"dateTime": _dt_to_rfc3339(end_dt), "timeZone": tz},
        }
        cal_svc.events().insert(calendarId="primary", body=ev).execute()
        return True
    except Exception as e:
        logging.error(f"Calendar add failed: {e}")
        return False

def _calendar_upcoming(cal_svc, tz: str = DEFAULT_TZ, max_results: int = 10):
    now = datetime.datetime.now(ZoneInfo(tz))
    try:
        items = cal_svc.events().list(
            calendarId="primary",
            timeMin=_dt_to_rfc3339(now),
            maxResults=max_results,
            singleEvents=True,
            orderBy="startTime",
        ).execute().get("items", [])
        return items
    except Exception as e:
        logging.error(f"Calendar list failed: {e}")
        return []

def _calendar_event_speech_line(ev, tz: str = DEFAULT_TZ) -> str:
    """
    Format calendar event for voice review without timezone offset.
    Output examples:
      - Meeting on 2026-05-25 at 11:30
      - Holiday on 2026-05-25 all day
    """
    summ = ev.get("summary") or "Untitled event"
    start = ev.get("start", {}) or {}
    raw_dt = start.get("dateTime")
    raw_date = start.get("date")

    if raw_dt:
        try:
            dt = datetime.datetime.fromisoformat(raw_dt.replace("Z", "+00:00"))
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=ZoneInfo(tz))
            dt = dt.astimezone(ZoneInfo(tz))
            return f"{summ} on {dt.strftime('%Y-%m-%d')} at {dt.strftime('%H:%M')}"
        except Exception:
            # Fallback: remove timezone part if parsing ever fails
            clean = re.sub(r"(Z|[+-]\d{2}:\d{2})$", "", raw_dt)
            clean = clean.replace("T", " ")
            clean = clean[:16]
            return f"{summ} at {clean}"

    if raw_date:
        return f"{summ} on {raw_date} all day"

    return summ

def _calendar_cancel_by_title(cal_svc, title_sub: str, tz: str = DEFAULT_TZ) -> int:
    """
    Cancels upcoming events whose summary contains title_sub (case-insensitive).
    Returns number deleted.
    """
    title_sub = (title_sub or "").strip().lower()
    if not title_sub:
        return 0
    now = datetime.datetime.now(ZoneInfo(tz)) - datetime.timedelta(days=1)
    try:
        items = cal_svc.events().list(
            calendarId="primary",
            timeMin=_dt_to_rfc3339(now),
            maxResults=50,
            singleEvents=True,
            orderBy="startTime",
            q=title_sub
        ).execute().get("items", [])
    except Exception as e:
        logging.error(f"Calendar search failed: {e}")
        return 0

    deleted = 0
    for ev in items:
        summ = (ev.get("summary") or "").lower()
        if title_sub in summ:
            try:
                cal_svc.events().delete(calendarId="primary", eventId=ev["id"]).execute()
                deleted += 1
            except Exception as e:
                logging.error(f"Calendar delete failed: {e}")
    return deleted

def _gmail_recent_subjects(max_results: int = 5, subject_count: int = 3):
    svc = get_gmail_service()
    if not svc:
        return None, "Gmail not configured."

    try:
        results = svc.users().messages().list(userId="me", labelIds=["INBOX"], q="in:inbox", maxResults=max_results).execute()
        msgs = results.get("messages", []) or []
        subjects = []
        for m in msgs[:subject_count]:
            meta = svc.users().messages().get(
                userId="me",
                id=m["id"],
                format="metadata",
                metadataHeaders=["Subject"]
            ).execute()
            hdrs = meta.get("payload", {}).get("headers", []) or []
            subj = ""
            for h in hdrs:
                if (h.get("name") or "").lower() == "subject":
                    subj = h.get("value") or ""
                    break
            subjects.append(subj.strip() if subj else "(no subject)")
        return {"count": len(msgs), "subjects": subjects}, None
    except Exception as e:
        logging.error(f"Gmail subject read failed: {e}")
        return None, "Failed to read email subjects."
def agent_decision_from_groq(user_text, system_prompt=AGENT_SYSTEM_PROMPT):
    try:
        cc = groq_client.chat.completions.create(
            messages=[{"role":"system","content":system_prompt},{"role":"user","content":user_text}],
            model=GROQ_CHAT_MODEL, temperature=0.0, max_tokens=512
        )
        return cc.choices[0].message.content.strip()
    except Exception as e:
        logging.error(f"Groq agent decision failed: {e}"); return None

def process_agent_command(user_text: str):
    """
    FULL agent behavior (deterministic, no Groq guessing) for:
    - Notes: review/add/remove (contiguous numbering via num)
    - Tasks: review/add/remove (contiguous numbering via num)
    - Calendar: review/add/cancel
    - Email: review subjects
    """
    cmd = (user_text or "").strip().lower()

    # ---------------------------
    # NOTES / TASKS: ADD (single step, no "how many")
    # Examples:
    #   "add note clean the room"
    #   "add note (clean the room)"
    #   "include note buy milk"
    #   "add task submit report"
    # ---------------------------
    m = re.search(r"\b(?:add|include)\s+note(?:s)?\b(.*)", cmd)
    if m:
        text = (m.group(1) or "").strip(" .,:;-").strip()
        if (text.startswith("(") and text.endswith(")")) or (text.startswith("[") and text.endswith("]")):
            text = text[1:-1].strip()

        if not text:
            play_tts_response("Please say the note text after add note. For example: add note clean the room.")
            return True

        num = _add_item("notes", text)
        if num is None:
            play_tts_response("Sorry, I could not save the note.")
        else:
            play_tts_response(f"Saved note {num}.")
        return True

    m = re.search(r"\b(?:add|include)\s+task(?:s)?\b(.*)", cmd)
    if m:
        text = (m.group(1) or "").strip(" .,:;-").strip()
        if (text.startswith("(") and text.endswith(")")) or (text.startswith("[") and text.endswith("]")):
            text = text[1:-1].strip()

        if not text:
            play_tts_response("Please say the task text after add task. For example: add task submit report.")
            return True

        num = _add_item("tasks", text)
        if num is None:
            play_tts_response("Sorry, I could not save the task.")
        else:
            play_tts_response(f"Saved task {num}.")
        return True

    # ---------------------------
    # NOTES / TASKS: REVIEW
    # ---------------------------
    if re.search(r"\b(review|what'?s|whats)\s+(on\s+)?my\s+notes\b", cmd) or "review my note" in cmd or "what's on my note" in cmd:
        rows = _list_items("notes", limit=10)
        if not rows:
            play_tts_response("You have no notes.")
            return True
        speak_rows = rows[-5:]
        lines = [f"Note {num}: {txt}" for num, txt, _ in speak_rows]
        play_tts_response("Here are your latest notes. " + " . ".join(lines))
        return True

    if re.search(r"\b(review|what'?s|whats)\s+(on\s+)?my\s+tasks\b", cmd) or "review my task" in cmd or "what's on my task" in cmd:
        rows = _list_items("tasks", limit=10)
        if not rows:
            play_tts_response("You have no tasks.")
            return True
        speak_rows = rows[-5:]
        lines = [f"Task {num}: {txt}" for num, txt, _ in speak_rows]
        play_tts_response("Here are your latest tasks. " + " . ".join(lines))
        return True

    # ---------------------------
    # NOTES / TASKS: REMOVE (remove/delete/detete) by visible number
    # Examples:
    #   "remove note 3"
    #   "delete note 3"
    #   "delete notes 3"
    #   "delete task 2"
    #   "detete task 2"   (STT typo)
    # ---------------------------
    m = re.search(r"\b(?:remove|delete|detete)\s+note(?:s)?\s+(\d+)\b", cmd)
    if m:
        note_num = int(m.group(1))
        if _delete_item_by_id("notes", note_num):
            play_tts_response(f"Note {note_num} removed.")
        else:
            play_tts_response(f"I could not find note {note_num}.")
        return True

    m = re.search(r"\b(?:remove|delete|detete)\s+task(?:s)?\s+(\d+)\b", cmd)
    if m:
        task_num = int(m.group(1))
        if _delete_item_by_id("tasks", task_num):
            play_tts_response(f"Task {task_num} removed.")
        else:
            play_tts_response(f"I could not find task {task_num}.")
        return True

    # ---------------------------
    # CALENDAR: REVIEW
    # ---------------------------
    if ("review my calender" in cmd) or ("review my calendar" in cmd) or ("what's on my calender" in cmd) or ("what's on my calendar" in cmd):
        cal = get_calendar_service()
        if not cal:
            play_tts_response("Calendar not configured.")
            return True

        items = _calendar_upcoming(cal, tz=DEFAULT_TZ, max_results=10)
        if not items:
            play_tts_response("You have no upcoming calendar events.")
            return True

        speak_items = items[:3]
        parts = [_calendar_event_speech_line(ev, tz=DEFAULT_TZ) for ev in speak_items]
        play_tts_response(f"You have {len(items)} upcoming events. The next ones are: " + " . ".join(parts))
        return True

    # ---------------------------
    # CALENDAR: ADD EVENT (day first, then month+year, then time, then title)
    # ---------------------------
    if ("set calender event" in cmd) or ("set calendar event" in cmd):
        cal = get_calendar_service()
        if not cal:
            play_tts_response("Calendar not configured.")
            return True

        # Step 1: Day
        play_tts_response("Please say the day number only. For example: 1, or 12.")
        day_text = get_audio_input()
        day = _parse_day_only(day_text or "")
        if not day:
            play_tts_response("Sorry, I could not understand the day. Please try again. Say only the day number.")
            day_text = get_audio_input()
            day = _parse_day_only(day_text or "")
            if not day:
                play_tts_response("Sorry, I still could not understand the day.")
                return True

        # Step 2: Month + Year
        play_tts_response("Now say the month and year. For example: March 2026.")
        my_text = get_audio_input()
        my = _parse_month_year(my_text or "", tz=DEFAULT_TZ)
        if not my:
            play_tts_response("Sorry, I could not understand the month and year. Please try again. Example: March 2026.")
            my_text = get_audio_input()
            my = _parse_month_year(my_text or "", tz=DEFAULT_TZ)
            if not my:
                play_tts_response("Sorry, I still could not understand the month and year.")
                return True

        month, year = my

        # Validate the date (handles 31 April etc.)
        try:
            d = datetime.date(int(year), int(month), int(day))
        except Exception:
            play_tts_response("That date is not valid. Please try setting the event again.")
            return True

        # Time
        play_tts_response("What time? Please say in 24 hour format. For example: 14 30.")
        ttext = get_audio_input()
        hm = _parse_time_input_24h(ttext or "", tz=DEFAULT_TZ)
        if not hm:
            play_tts_response("Sorry, I could not understand the time.")
            return True
        hh, mm = hm

        # Title
        play_tts_response("What is the title of the event?")
        title = (get_audio_input() or "").strip()
        if not title:
            play_tts_response("Sorry, I did not catch the title.")
            return True

        start_dt = datetime.datetime(d.year, d.month, d.day, hh, mm, tzinfo=ZoneInfo(DEFAULT_TZ))
        end_dt = start_dt + datetime.timedelta(minutes=60)

        if not _calendar_slot_is_free(cal, start_dt, end_dt):
            play_tts_response("Sorry, the schedule already booked.")
            return True

        if _calendar_add_event(cal, title, start_dt, end_dt, tz=DEFAULT_TZ):
            play_tts_response(f"Event added. {title} on {d.isoformat()} at {hh:02d}:{mm:02d}.")
        else:
            play_tts_response("Sorry, I could not add the event.")
        return True

    # ---------------------------
    # CALENDAR: CANCEL EVENT by title
    # (requires word "event" so it won't break cancel timer)
    # ---------------------------
    if cmd.startswith("cancel") and "event" in cmd:
        cal = get_calendar_service()
        if not cal:
            play_tts_response("Calendar not configured.")
            return True

        parts = cmd.split("event", 1)
        title_sub = (parts[1] if len(parts) > 1 else "").strip()
        if not title_sub:
            title_sub = re.sub(r"\bcancel\b", "", cmd).strip()
            title_sub = re.sub(r"\b(calendar|calender)\b", "", title_sub).strip()
            title_sub = re.sub(r"\bevent\b", "", title_sub).strip()

        if not title_sub:
            play_tts_response("Please say the event title you want to cancel.")
            return True

        deleted = _calendar_cancel_by_title(cal, title_sub, tz=DEFAULT_TZ)
        if deleted > 0:
            play_tts_response(f"Cancelled {deleted} event(s) matching {title_sub}.")
        else:
            play_tts_response(f"I could not find any event matching {title_sub}.")
        return True

    # ---------------------------
    # EMAIL: REVIEW (count + first 3 subjects)
    # ---------------------------
    if ("review my email" in cmd) or ("what's on my email" in cmd) or ("whats on my email" in cmd) or ("review my mail" in cmd):
        data, err = _gmail_recent_subjects(max_results=5, subject_count=3)
        if err:
            play_tts_response(err)
            return True

        count = data["count"]
        subs = data["subjects"]
        if count <= 0:
            play_tts_response("You have no inbox emails.")
            return True

        if subs:
            play_tts_response(
                f"You have {count} inbox emails. The latest inbox subjects are: "
                f"1, {subs[0]}. 2, {subs[1] if len(subs)>1 else ''}. 3, {subs[2] if len(subs)>2 else ''}."
            )
        else:
            play_tts_response(f"You have {count} inbox emails.")
        return True

    play_tts_response("Sorry, I didn't recognize that agent request.")
    return True
# ---- OTP store ----
_otp_store: Dict[str, Dict[str, float]] = {}
_otp_lock = Lock()
_OTP_TTL_SECONDS = 300

def _set_otp(student_id: str, otp: str):
    with _otp_lock:
        _otp_store[student_id] = {"otp": otp, "exp": time.time() + _OTP_TTL_SECONDS}

def _get_otp(student_id: str) -> Optional[str]:
    with _otp_lock:
        rec = _otp_store.get(student_id)
        if not rec: return None
        if rec["exp"] < time.time():
            _otp_store.pop(student_id, None); return None
        return rec["otp"]

def generate_and_send_otp(student_id: str, student_name: str, email: str) -> bool:
    if not email:
        play_tts_response("Your email is not registered. Please contact the lab supervisor."); return False
    otp = f"{random.randint(1000, 9999)}"
    _set_otp(student_id, otp)
    subject = f"Your Lab OTP: {otp}"
    body = (f"Hello {student_name},\n\nYour one-time password (OTP) for lab locker access is: {otp}\n"
            f"This code expires in 5 minutes.\n\nRegards,\nElectronics Lab Assistant (ELA)\n")
    ok, msg = send_simple_email(email, subject, body)
    if not ok:
        logging.error(f"Failed to send OTP to {email}: {msg}")
        play_tts_response("Sorry, I could not send the verification code to your email.")
        return False
    return True

def verify_spoken_otp(student_id: str, max_attempts: int = 2) -> bool:
    for attempt in range(max_attempts):
        play_tts_response("Please say the four digit verification code.")
        spoken = get_audio_input()
        digits = parse_id_digits(spoken or "")
        otp = _get_otp(student_id)
        if not otp:
            play_tts_response("The verification code expired. I will send a new one."); return False
        if digits and digits == otp:
            return True
        if attempt < max_attempts - 1:
            play_tts_response("That does not match. Try again.")
    return False

