# Availability (kept + extended by component-only handler)
RE_HOW_MANY  = re.compile(r"\bhow\s+many\s+([a-z0-9 _-]+)\s+available\b", re.I)
RE_CAN_I_GET = re.compile(r"\bcan\s+i\s+get\s+(?:an?\s+)?([a-z0-9 _-]+)\b", re.I)
RE_WHERE_GET = re.compile(r"\bwhere\s+i\s+can\s+get\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I)
RE_IS_THERE_ANY = re.compile(r"\bis\s+there\s+(?:any|an?|some)\s+([a-z0-9 _-]+)\s+available\b", re.I)

# - "i want to get X" / "i want to ger X"
# - "want to get X"
# - "give me X"
# - "i need X"
RE_BORROW_PHRASES = [
    re.compile(r"\bi\s+want\s+to\s+g(?:e|a)r\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),  # ger/get (STT typo)
    re.compile(r"\bi\s+want\s+to\s+get\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
    re.compile(r"\bwant\s+to\s+get\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
    re.compile(r"\bgive\s+me\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
    re.compile(r"\bi\s+need\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
]

# - "i want to return X"
# - "want to return X"
# - "return X"
RE_RETURN_PHRASES = [
    re.compile(r"\bi\s+want\s+to\s+return\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
    re.compile(r"\bwant\s+to\s+return\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
    re.compile(r"\breturn\s+(?:an?\s+)?([a-z0-9 _-]+)", re.I),
]

RE_LIST_ALL  = re.compile(r"\blist\s+all\s+components\b", re.I)

def _availability_response(name, qty, location):
    return (f"Oh, {name}, we have total {qty} {name} at this moment in our lab which is available at {location}. "
            f"If you want to borrow just tell me: I want to get {name}.")

def handle_where_can_i_get(cmd: str) -> bool:
    m = RE_WHERE_GET.search(cmd) or RE_IS_THERE_ANY.search(cmd) or RE_CAN_I_GET.search(cmd)
    if not m: return False
    comp = resolve_component_name(m.group(1))
    row = get_component(comp)
    if not row:
        play_tts_response(f"I can't find {comp} in the lab inventory."); return True
    name, qty, location, locker = row
    play_tts_response(_availability_response(name, qty, location))
    return True

def handle_how_many_available(cmd: str) -> bool:
    m = RE_HOW_MANY.search(cmd)
    if not m: return False
    comp = resolve_component_name(m.group(1))
    row = get_component(comp)
    if not row: play_tts_response(f"I can't find {comp} in inventory."); return True
    name, qty, location, _ = row
    play_tts_response(_availability_response(name, qty, location))
    return True

# Examples:
# - "arduino"
# - "arena" (alias)
# - "seven segment"
# Safe guards: ignore if command looks like other features (music/weather/timer/etc) or is super ambiguous alias alone.
_NON_COMPONENT_KEYWORDS = (
    "music","song","timer","weather","open","door","learn","learning","face","object","look","picture","vision",
    "hand","leg","data","light","led","email","mail","calendar","appointment","event","note","notes","remind","schedule"
)
def handle_component_only_availability(cmd: str) -> bool:
    if not cmd:
        return False
    lc = (cmd or "").lower()
    if any(k in lc for k in _NON_COMPONENT_KEYWORDS):
        return False

    cleaned = _clean_component_text(cmd)
    cleaned = re.sub(r"\b(available|in stock|stock)\b", "", cleaned).strip()
    cleaned = re.sub(r"^(can i get|where i can get|is there any|how many)\s+", "", cleaned).strip()
    cleaned = re.sub(r"\s+", " ", cleaned)

    if not cleaned:
        return False

    if cleaned in _AMBIGUOUS_SINGLETON_ALIASES and len(cleaned.split()) == 1:
        return False

    # keep it short-ish (avoid triggering on long general sentences)
    if len(cleaned.split()) > 3:
        return False

    comp = resolve_component_name(cleaned)
    row = get_component(comp)
    if not row:
        return False

    name, qty, location, _ = row
    play_tts_response(_availability_response(name, qty, location))
    return True

# ====================================================
# - If the command is lab/component-related and contains a component alias, print canonical names.
# - Non-lab commands print exactly as-is.
# ====================================================
def _is_component_context_for_console(cmd: str) -> bool:
    if not cmd:
        return False
    lc = (cmd or "").lower().strip()

    # If it looks like other features (music/weather/timer/etc), don't touch it.
    if any(k in lc for k in _NON_COMPONENT_KEYWORDS):
        return False

    # Explicit lab intents
    if RE_HOW_MANY.search(lc) or RE_CAN_I_GET.search(lc) or RE_WHERE_GET.search(lc) or RE_IS_THERE_ANY.search(lc):
        return True
    for rx in (RE_BORROW_PHRASES + RE_RETURN_PHRASES):
        if rx.search(lc):
            return True
    if RE_LIST_ALL.search(lc):
        return True

    # Component-only short commands (same safety rules as handler)
    cleaned = _clean_component_text(lc)
    cleaned = re.sub(r"\b(available|in stock|stock)\b", "", cleaned).strip()
    cleaned = re.sub(r"^(can i get|where i can get|is there any|how many)\s+", "", cleaned).strip()
    cleaned = re.sub(r"\s+", " ", cleaned)

    if not cleaned:
        return False
    if cleaned in _AMBIGUOUS_SINGLETON_ALIASES and len(cleaned.split()) == 1:
        return False
    if len(cleaned.split()) > 3:
        return False

    comp = resolve_component_name(cleaned)
    return bool(get_component(comp))

def normalize_command_for_console(cmd: str) -> str:
    """
    DISPLAY ONLY: Replace component aliases inside the command with canonical component names,
    but ONLY when the command is clearly lab/component-related.
    """
    if not cmd:
        return cmd
    if not _is_component_context_for_console(cmd):
        return cmd

    out = (cmd or "").lower()
    # Help match aliases like "7-segment" (STT sometimes includes '-')
    out = out.replace("-", " ")
    out = re.sub(r"\s+", " ", out).strip()

    # Replace longest aliases first (so "seven segment" wins over "seven")
    for alias in sorted(_ALIAS_TO_CANON.keys(), key=len, reverse=True):
        canon = _ALIAS_TO_CANON[alias]

        # Skip super-ambiguous singletons (avoid "play" => "display" etc.)
        if alias in _AMBIGUOUS_SINGLETON_ALIASES and " " not in alias:
            continue

        out = re.sub(rf"(?<!\w){re.escape(alias)}(?!\w)", canon, out, flags=re.I)

    out = re.sub(r"\s+", " ", out).strip()
    return out if out else cmd

def _prompt_student_identity_and_quantity(item_name: str):
    play_tts_response("Tell me your student I D. Speak only digits, for example: two two three three.")
    sid_in = get_audio_input()
    sid_digits = parse_id_digits(sid_in or "")
    if not sid_digits:
        return None, None, None, "no-id"

    stu = get_student(sid_digits)
    if not stu:
        return None, None, None, "unknown-id"
    sid, sname, semail = stu

    for attempt in range(2):
        # ? First ask: no example (prevents duplication)
        if attempt == 0:
            play_tts_response(
                f"Hi {sname}. How many {item_name}? "
                f"You can also say just the number."
            )
        # ? Retry: say the example only once
        else:
            play_tts_response(
                f"Sorry, I didn't catch the quantity. Please say like: five {item_name}. "
                f"You can also say just the number."
            )

        qtext = get_audio_input()
        want_qty = parse_component_quantity(qtext or "")
        if want_qty and want_qty > 0:
            break
    else:
        return None, None, None, "bad-qty"

    play_tts_response("I will send a four digit verification code to your registered email.")
    if not generate_and_send_otp(sid, sname, semail):
        return None, None, None, "otp-send-failed"

    if not verify_spoken_otp(sid):
        return None, None, None, "otp-mismatch"

    return (sid, sname, want_qty, None)
def handle_borrow_component_flow(component_name: str) -> bool:
    row = get_component(component_name)
    if not row:
        play_tts_response(f"{component_name} is not in the inventory.")
        return True

    name, qty, location, locker = row

    sid, sname, want_qty, err = _prompt_student_identity_and_quantity(name)
    if err == "no-id":
        play_tts_response("I did not catch a numeric ID. Access denied.")
        return True
    if err == "unknown-id":
        play_tts_response("ID not recognized. Access denied.")
        return True
    if err == "bad-qty":
        play_tts_response("Invalid quantity.")
        return True
    if err == "otp-send-failed":
        play_tts_response("Verification code could not be sent. Access denied.")
        return True
    if err == "otp-mismatch":
        play_tts_response("Verification failed. Access denied.")
        return True

    stu_row = get_student(str(sid))
    semail = (stu_row[2] if stu_row and len(stu_row) >= 3 else "") or ""

    ok, remaining, info = atomic_borrow(name, want_qty)
    if not ok:
        if info == "insufficient-stock":
            play_tts_response(f"Only {qty} {name} available now.")
        elif info == "not-found":
            play_tts_response(f"{name} is not in the inventory.")
        else:
            play_tts_response("Inventory update failed.")
        return True

    try:
        locker_to_open = info["locker"]
        location_str = info["location"]
        mqtt_client.publish(LOCKER_TOPIC, f"OPEN_LOCKER:{locker_to_open}")
    except Exception:
        logging.error("MQTT publish failed")
        play_tts_response("Locker control failed.")
        return True

    # Track borrow (NEW)
    borrow_dt_utc, due_dt_utc = add_borrow_txn(sid, sname, semail, name, want_qty)

    log_borrow(sid, sname, name, want_qty, remaining)

    # Email to LAB (keep your excel attachment)
    att = []
    b = export_components_excel()
    if b:
        att.append(("components.xlsx", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", b))

    body = (
        f"Borrow record\n"
        f"- Student: {sname} (ID {sid})\n"
        f"- Student email: {semail}\n"
        f"- OTP verified\n"
        f"- Item: {name}\n"
        f"- Quantity: {want_qty}\n"
        f"- Locker opened: {locker_to_open} ({location_str})\n"
        f"- Remaining stock: {remaining}\n"
        f"- Borrow time (UTC): {borrow_dt_utc.isoformat(timespec='seconds')}\n"
        f"- Due time (UTC): {due_dt_utc.isoformat(timespec='seconds')}\n"
    )
    send_email_with_attachment(LAB_EMAIL, f"Borrowed {want_qty}x {name} by {sname} ({sid})", body, att)

    # Email to STUDENT (NEW, no attachment)
    if semail.strip():
        try:
            b_local = borrow_dt_utc.astimezone(ZoneInfo(DEFAULT_TZ))
            d_local = due_dt_utc.astimezone(ZoneInfo(DEFAULT_TZ))
            b_str = b_local.strftime("%Y-%m-%d %H:%M")
            d_str = d_local.strftime("%Y-%m-%d %H:%M")
        except Exception:
            b_str = borrow_dt_utc.isoformat(timespec="seconds")
            d_str = due_dt_utc.isoformat(timespec="seconds")

        stu_subject = f"Lab Borrow Confirmation: {want_qty}x {name}"
        stu_body = (
            f"Hello {sname},\n\n"
            f"This email confirms your lab borrow.\n\n"
            f"Component: {name}\n"
            f"Quantity: {want_qty}\n"
            f"Borrow date: {b_str}\n"
            f"Due date (2 months): {d_str}\n\n"
            f"Please return the component(s) before the due date.\n\n"
            f"Regards,\nElectronics Lab Assistant (ELA)\n"
        )
        send_simple_email(semail, stu_subject, stu_body)

    play_tts_response(
        f"Access granted. Opening locker {locker_to_open}. "
        f"{want_qty} {name} registered. Remaining stock {remaining}."
    )
    return True

