UNKNOWN_COMMAND_REPLY = "Please provide me exact command to get your desire service"

INFO_TRIGGER_RE = re.compile(
    r"\b(i\s+need\s+information|i\s+need\s+some\s+information|i\s+want\s+information|give\s+me\s+information)\b",
    re.I
)

def ask_groq_uncommon_question() -> bool:
    """
    Separate one-time uncommon question mode.
    Trigger:
        User says: "I need information"
    Robot:
        Asks: "What information do you need?"
        Listens one time
        Sends only that question to GROQ_CHAT_MODEL
        Speaks the answer
        Returns to normal workflow
    """
    play_tts_response("What information do you need?")

    question = get_audio_input()
    question = (question or "").strip()

    if not question:
        play_tts_response("Sorry, I could not hear your question.")
        return True

    try:
        with GROQ_LOCK:
            resp = groq_client.chat.completions.create(
                model=GROQ_CHAT_MODEL,
                messages=[
                    {
                        "role": "system",
                        "content": (
                            "You are ELLA, a helpful humanoid robot assistant. "
                            "Answer the user's uncommon information question clearly and briefly. "
                            "Do not call tools. Do not give robot control commands. "
                            "Keep the answer suitable for spoken response."
                        )
                    },
                    {
                        "role": "user",
                        "content": question
                    }
                ],
                temperature=0.4,
                max_tokens=250
            )

        answer = resp.choices[0].message.content.strip()

        if not answer:
            answer = "Sorry, I could not find a proper answer."

        play_tts_response(answer)
        return True

    except Exception as e:
        logging.error(f"Groq uncommon question error: {e}")
        play_tts_response("Sorry, I could not get that information right now.")
        return True

def process_command(command):
    command = (command or "").strip().lower()
    logging.info(f"Processing command: {command}")

    display_cmd = normalize_command_for_console(command)
    print(f"Detected command: {display_cmd}")

    _set_last_command_for_display(command)

        # uncommon information mode: only this trigger uses GROQ_CHAT_MODEL
    if INFO_TRIGGER_RE.search(command):
        return ask_groq_uncommon_question()

    # availability/info first
    if handle_where_can_i_get(command):
        return True
    if handle_how_many_available(command):
        return True
    if handle_component_only_availability(command):
        return True

    # lab flows
    if handle_borrow_command(command):
        return True
    if handle_return_command(command):
        return True

    if handle_list_all_components(command):
        return True
    if handle_import_export_excel(command):
        return True

    # learning intent
    m = re.search(r"\blearning\s+person[, ]+\s*this\s+is\s+([a-zA-Z0-9 _-]+)", command, re.I)
    if m:
        return learn_face(m.group(1).strip(" ()"))

    m = re.search(r"\blearning\s+face[, ]+\s*this\s+is\s+([a-zA-Z0-9 _-]+)", command, re.I)
    if m:
        return learn_face(m.group(1).strip(" ()"))

    m = re.search(r"\blearning\s+object[, ]+\s*that\s+is\s+([a-zA-Z0-9 _-]+)", command, re.I)
    if m:
        return learn_object(m.group(1).strip(" ()"))

    m = re.search(r"\blearn\s+face[, ]+(?:name\s+)?([a-zA-Z0-9 _-]+)", command, re.I)
    if m:
        return learn_face(m.group(1).strip(" ()"))

    m = re.search(r"\blearn\s+that[, ]+\s*this\s+is\s+([a-zA-Z0-9 _-]+)", command, re.I)
    if m:
        return learn_object(m.group(1).strip(" ()"))

    # recognition
    if re.search(r"\bwho\s+is\s+that\??", command, re.I):
        recognize_face()
        return True

    if re.search(r"\bwhat\s+is\s+that\??", command, re.I):
        recognize_object()
        return True

    # agent keywords
    lc_cmd = command
    if any(k in lc_cmd for k in [
        "email", "mail",
        "calendar", "calender", "appointment", "event",
        "note", "notes", "task", "tasks",
        "include note", "add note", "add task", "add notes", "add tasks", "include notes",
        "include task", "include tasks",
        "review my notes", "review my tasks",
        "what's on my notes", "whats on my notes",
        "what's on my tasks", "whats on my tasks",
        "review my calendar", "review my calender",
        "what's on my calendar", "whats on my calendar",
        "what's on my calender", "whats on my calender",
        "set calendar event", "set calender event",
        "remove note", "remove task",
        "delete note", "delete notes", "delete task", "delete tasks",
        "detete note", "detete notes", "detete task", "detete tasks",
    ]):
        return process_agent_command(command)

    # self-learn summary
    if re.search(r"\bwhat\s+did\s+you\s+(?:self\s+)?learn\b", lc_cmd):
        return speak_what_i_learned()

    # weather
    if "weather" in command:
        m = re.search(r"\bweather\b.*?\bin\s+([a-z0-9 _-]+)\b", command, re.I)
        city = m.group(1).strip() if m else None

        if not city:
            m2 = re.search(r"^([a-z0-9 _-]+)\s+weather\b", command.strip(), re.I)
            city = m2.group(1).strip() if m2 else None

        play_tts_response(get_weather(city))
        return True

    # data collection
    if "data collection" in command:
        Thread(target=collect_data, daemon=True).start()
        return True

    # motion
    if "hand movement" in command or "move hand" in command:
        Thread(target=hand, daemon=True).start()
        return True

    if "leg movement" in command or "go forward" in command or "leg move" in command:
        Thread(target=leg, daemon=True).start()
        return True

    if "right movement" in command or "go right" in command:
        Thread(target=right, daemon=True).start()
        return True

    if "left movement" in command or "go left" in command:
        Thread(target=left, daemon=True).start()
        return True

    # timers
    if "set timer" in command or ("timer" in command and "set" in command):
        d = parse_duration(command)
        if d:
            start_timer(d)
            play_tts_response(f"Timer set for {d//60} minutes and {d%60} seconds.")
        else:
            play_tts_response("Sorry, I couldn't understand the timer duration.")
        return True

    if "cancel timer" in command or "stop timer" in command:
        cancel_all_timers()
        return True

    # canned
    if command in CUSTOM_RESPONSES:
        play_tts_response(CUSTOM_RESPONSES[command])
        return True

    # lights
    if "turn on" in command and "light" in command:
        mqtt_client.publish(MQTT_TOPIC, "ON")
        play_tts_response("LED turned on.")
        return True

    if "turn off" in command and "light" in command:
        mqtt_client.publish(MQTT_TOPIC, "OFF")
        play_tts_response("LED turned off.")
        return True

    # music
    if "stop music" in command or ("music" in command and "stop" in command):
        stop_music()
        return True

    if "play" in command and ("music" in command or "song" in command):
        if "party" in command:
            play_music("party")
        elif "emotional" in command:
            play_music("emotional")
        elif "random" in command:
            play_music()
        elif any(k in command for k in ["rock", "classical", "jazz"]):
            if "rock" in command:
                play_music("rock")
            elif "classical" in command:
                play_music("classical")
            elif "jazz" in command:
                play_music("jazz")
        else:
            words = command.replace("play", "").replace("music", "").replace("song", "").strip().split()
            track = "_".join(words) + ".mp3" if words else None
            play_music("general", track)
        return True

    # legacy door
    if "open the door" in command:
        play_tts_response("Tell me your ID. Speak only digits.")
        uid_text = get_audio_input()
        uid = parse_id_digits(uid_text or "")
        if uid and uid in AUTHORIZED_IDS:
            mqtt_client.publish("robot/servo", "OPEN_DOOR")
            play_tts_response(f"Hello {AUTHORIZED_IDS[uid]}, Door is opening.")
        else:
            play_tts_response("ID not recognized. Access denied.")
        return True

    # vision describe
    if any(w in command for w in ["look", "picture", "what do you see", "see", "vision", "describe"]):
        st = Thread(target=vision_servo_movement, daemon=True)
        st.start()
        time.sleep(0.5)

        image_path = capture_image()
        if image_path:
            try:
                resp = groq_client.chat.completions.create(
                    messages=[{
                        "role": "user",
                        "content": [
                            {"type": "text", "text": "Give me a short answer, what do you see in this image?"},
                            {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{encode_image(image_path)}"}}
                        ]
                    }],
                    model=GROQ_VISION_MODEL
                )
                txt = resp.choices[0].message.content.strip()
                ans = f"I see {txt[0].lower() + txt[1:]}" if txt else "I see something, but couldn't describe it."
            except Exception:
                logging.error("Vision error")
                ans = "I'm sorry, I couldn't analyze the image."
        else:
            ans = "I'm sorry, I couldn't capture the image. Try again?"

        st.join()
        play_tts_response(ans)
        return True

    # unknown command: no GROQ_CHAT_MODEL fallback anymore
    play_tts_response(UNKNOWN_COMMAND_REPLY)
    return True

# ---- main loop ----
def wake_word_detected(text):
    if not text: return False
    return bool(WAKE_RE.search(text))

def extract_command(text):
    if not text: return ""
    return WAKE_RE.sub("", text, count=1).strip()

def _init_boot():
    _ensure_storage_dirs()
    init_learning_indexes()

    if not FACE_LIB_AVAILABLE:
        logging.warning("face_recognition not available.")
    if not OBJECT_LIB_AVAILABLE:
        logging.warning("OpenCV not available.")

    ensure_lab_db()
    seed_defaults_if_empty()

    # Start overdue reminder loop (NEW)
    try:
        Thread(target=overdue_reminder_loop, daemon=True).start()
        logging.info("Overdue reminder loop started.")
    except Exception as e:
        logging.error(f"Failed to start overdue reminder loop: {e}")

    # Selflearn DB + self-discovery loop
    try:
        ensure_selflearn_db()
        _selflearn_rebuild_index()
        Thread(target=self_discovery_loop, daemon=True).start()
        logging.info("Self-discovery loop started.")
    except Exception as e:
        logging.error(f"Failed to start self-discovery loop: {e}")
_init_boot()

try:
    logging.info("Starting Ela. Say 'Ela' to activate me.")
    last_activity_time, is_active = 0, False

    # NEW: initial state (starts in sleep)
    set_robot_active(False)

    while True:
        now = time.time()

        # Sleep transition
        if is_active and (now - last_activity_time > ACTIVE_DURATION):
            is_active = False
            set_robot_active(False)  # NEW
            play_tts_response("Going to sleep. Say 'Ela' when you need me.")
            logging.info("Sleep mode")

        ui = get_audio_input()
        if ui:
            logging.info(f"Heard: {ui}")
            last_activity_time = now

            if is_active or wake_word_detected(ui):
                if not is_active:
                    is_active = True
                    set_robot_active(True)  # NEW
                    logging.info("Active mode")

                cmd = extract_command(ui) if wake_word_detected(ui) else ui
                if cmd:
                    _set_last_command_for_display(cmd)
                    if process_command(cmd):
                        last_activity_time = time.time()
                else:
                    play_tts_response("Yes? How can I help you?")
                    cmd = get_audio_input()
                    if cmd:
                        _set_last_command_for_display(cmd)
                        if process_command(cmd):
                            last_activity_time = time.time()
            else:
                logging.info("Wake word not detected; ignoring")
        else:
            time.sleep(0.5)

except KeyboardInterrupt:
    logging.info("Program terminated by user.")
finally:
    logging.info("Cleaning up GPIO")
    GPIO.cleanup()
